(function(){
 var DATA={"CA":{"name":"California","laws":[{"category":"organics-diversion","law":"AB 1826 (2014) + SB 1383 (2016)","status":"active","effective":"SB 1383 in effect Jan 1, 2022; enforcement and fines began Jan 1, 2024","scope":"All businesses, residents, and multifamily properties -- no tonnage threshold (the broadest law in the U.S.)","sectors":"Commercial and residential","source_label":"CalRecycle","source_url":"https://calrecycle.ca.gov/organics/slcp/","verified":"primary"},{"category":"foam-ban","law":"SB 54 (2022) -- Plastic Pollution Prevention and Packaging Producer Responsibility Act, EPS provision","status":"active","effective":"Jan 1, 2025 (triggered when the required 25% EPS recycling rate was not met)","scope":"Producers prohibited from selling, offering for sale, distributing, or importing EPS food service ware (takeout containers, cups, plates, bowls, clamshells) in or into California","sectors":"EPS food service ware producers -- defined broadly to include certain sellers and distributors placing product into the California market","source_label":"CalRecycle","source_url":"https://calrecycle.ca.gov/packaging/packaging-epr/","verified":"primary","footnote":"A producer-level ban (unlike other states' vendor-use bans). The Attorney General issued an enforcement advisory Dec 2, 2025; administrative penalties reach $50,000 per day per violation. Before SB 54, 128+ California cities and 12 counties had local foam bans. The parent statute's producer responsibility program is now carried under epr-packaging; the EPS provisions remain modeled here per the Oregon SB 543 convention, cross-referenced rather than double-counted."},{"category":"pfas-packaging","law":"AB 1200 (2021) -- Health and Safety Code section 109000","status":"active","effective":"Jan 1, 2023","scope":"Plant-fiber food packaging and food service ware (containers, take-out boxes, liners, wrappers, utensils, straws, plates, bowls, trays) containing regulated PFAS: intentionally added in any amount OR present at or above 100 ppm total organic fluorine","sectors":"Any person distributing, selling, or offering for sale in California, including shops and restaurants selling take-out; manufacturers must use the least toxic alternative when replacing PFAS","source_label":"California Legislature (leginfo)","source_url":"https://leginfo.legislature.ca.gov/faces/billTextClient.xhtml?bill_id=202120220AB1200","verified":"primary","footnote":"Only state pairing the intentionally-added test with a numeric 100 ppm total-organic-fluorine screen. Attorney General enforcement advisory issued Oct 17, 2023 under the Unfair Competition Law."},{"category":"truth-in-labeling","law":"AB 1201 (2021) -- compostable products labeling, Public Resources Code 42355-42358.5","status":"active","effective":"Jan 1, 2022 (AB 1201 operative date); underlying compostable and degradable claims law active since 2011-2013 (SB 567 era); USDA organic-input requirement for compostable products begins June 30, 2027 after a two-year CalRecycle extension","scope":"Products sold as compostable or home compostable must meet ASTM D6400-19 (plastics) or D6868-19 (plastic-coated fiber); home compostable claims require OK compost HOME certification; compostable consumer products must have total organic fluorine below 100 ppm and be labeled to distinguish them from noncompostable products; biodegradable-type terms on plastic products are restricted; compostable plastic bags must carry certification logos and green color signaling and may not display a chasing arrow resin code or recycling-type symbol","sectors":"Manufacturers and sellers of consumer products and packaging in California; Attorney General and local prosecutors enforce, with private UCL and CLRA exposure","source_label":"CalRecycle (Truth-in-Labeling Laws page)","source_url":"https://calrecycle.ca.gov/plastics/labeling/","verified":"primary","footnote":"The 100 ppm total organic fluorine requirement for compostable products intersects with the AB 1200 PFAS entry under pfas-packaging -- related but distinct statutes, not double-counted."},{"category":"truth-in-labeling","law":"SB 343 (2021) -- Truth in Recycling chasing-arrows restriction, Public Resources Code 42355.51","status":"scheduled","effective":"Oct 4, 2026 -- applies to products and packaging MANUFACTURED on or after that date (18 months after CalRecycle published the Material Characterization Study Final Findings on Apr 4, 2025); statute was signed Oct 2021 but the labeling restriction keys to the study","scope":"Prohibits the chasing arrows symbol, the word recyclable, or any other indication of recyclability on products or packaging unless the material meets all statutory criteria: collected by programs serving at least 60 percent of the California population, sorted into defined streams by facilities serving at least 60 percent of programs (the 60/60 thresholds), reclaimed consistent with the Basel Convention, and design and composition requirements. The burden of substantiation is on the business using CalRecycle study data","sectors":"Anyone selling or distributing products or packaging in California; enforced by the Attorney General, district attorneys, and city attorneys; violations serve as predicates for private Unfair Competition Law and false advertising suits","source_label":"CalRecycle (SB 343 Accurate Recycling Labels page)","source_url":"https://calrecycle.ca.gov/wcs/recyclinglabels/","verified":"primary","footnote":"LITIGATION FLAG: a coalition of 18 trade associations (California League of Food Producers et al.) filed suit Mar 17, 2026 in the Southern District of California challenging SB 343 on First and Fourteenth Amendment grounds; no injunction as of this pass, so the Oct 4, 2026 date stands. CalRecycle updated Table 2 of the findings June 24, 2026; full study revision due 2027. Applicability keys to manufacture date, not sale date."},{"category":"foodware-use","law":"Sustainable Packaging for the State of California Act of 2018 (SB 1335; Public Resources Code 42370-42370.7)","status":"active","effective":"Statute effective Jan 1, 2019; implementing regulations effective Dec 31, 2021 (OAL approval Dec 6, 2021); the prohibition operates against CalRecycle's List of Approved Food Service Packaging, initially published by the Mar 6, 2022 statutory deadline; recyclable and compostable acceptance thresholds rose from 60/50 percent to 75 percent on Jan 1, 2026","scope":"Food service facilities located in state-owned facilities, operating on or as concessionaires on state property, or under contract to provide food service to a state agency may not dispense prepared food in food service packaging (plates, cups, bowls, trays, hinged or lidded containers) unless the packaging type is on CalRecycle's List of Approved Food Service Packaging as reusable, recyclable, or compostable; listed items must also meet public-health criteria including a 100 ppm total organic fluorine cap (PFAS proxy) and regulated-metals limits; exemptions include beverage containers, straws, lids, utensils, plastic bags, pre-sealed off-premises packaging, and reused ceramic, porcelain, glass, or non-foil metal ware (AB 1570, 2021)","sectors":"Cafeterias, restaurants, delis, markets, catering operations, and concessionaires at state-owned facilities (including UC and CSU food courts and dormitories, corrections commissaries, fairs, and legislative offices) and businesses under contract to state agencies; CalRecycle administers, with Department of General Services contracting duties","source_label":"CalRecycle (SB 1335 Food Service Packaging at State Facilities)","source_url":"https://calrecycle.ca.gov/packaging/statefoodservice/","verified":"primary","footnote":"Scoped to state facilities -- California has no statewide foodware-use mandate for private food vendors generally, which is why the landmark local ordinances below are not subsumed. CalRecycle's approved-materials list includes plastic-free molded fiber from sugarcane bagasse and bamboo and clay-coated paperboard as meeting the compostable criteria. CalRecycle completed its first List reevaluation in Oct 2025 and removed discontinued products in spring 2026. The DGS contracting provisions of this act border the procurement category, now live on the map; under the who-is-bound test SB 1335 remains modeled here (it directly binds food service facilities), with its DGS contracting duties cross-referenced rather than double-counted as a separate procurement entry."},{"category":"epr-packaging","law":"SB 54 (2022) -- Plastic Pollution Prevention and Packaging Producer Responsibility Act (Public Resources Code 42040 et seq.)","status":"active","effective":"Signed June 30, 2022; permanent regulations approved and effective May 1, 2026 (Title 14 CCR chapter 11.1); producer registration -- join Circular Action Alliance, register with CalRecycle as an independent producer, or claim the small-producer exemption -- was due June 1, 2026; calendar-year-2023 baseline supply reports due July 1, 2026; program plan approval and program start by Jan 1, 2027, after which unregistered producers may not sell covered materials; $500 million per year Plastic Pollution Mitigation Fund surcharge from March 1, 2027; by Jan 1, 2032, 100 percent of single-use packaging and plastic food service ware must be recyclable or compostable, 65 percent of single-use plastic must be recycled (interim 30 percent by 2028 and 40 percent by 2030), and single-use plastic must be cut 25 percent from the 2023 baseline","scope":"Producers of single-use packaging and single-use plastic food service ware sold, distributed, or imported into California -- an estimated 5,700-plus producers, the largest state EPR program -- must register, report supply data, pay program fees, and meet source-reduction and recyclability-or-compostability requirements; Circular Action Alliance is the sole approved producer responsibility organization (draft program plan submitted June 15, 2026, public comment through Aug 14, 2026); recyclability and compostability of covered material categories are evaluated using the SB 343 criteria; the small-producer exemption is not self-executing and must be claimed through registration","sectors":"Producers -- generally brand or trademark owners, or importers where no in-state brand owner exists -- of single-use packaging and single-use plastic food service ware placed into California commerce","source_label":"CalRecycle (SB 54 permanent regulations)","source_url":"https://calrecycle.ca.gov/laws/rulemaking/sb54regulations/","verified":"primary","footnote":"LITIGATION FLAG: Nebraska v. Heller (E.D. Cal., filed June 22, 2026) -- 17 states plus the National Association of Wholesaler-Distributors challenge SB 54 on Commerce Clause, First Amendment, and private-delegation grounds; the complaint does not presently seek a preliminary injunction, no injunction exists, and SB 54 obligations remain fully active. Environmental groups (Californians Against Waste Foundation, NRDC, Oceana) separately petitioned in state court in June 2026 claiming the final regulations weaken the statute. The statute's EPS producer requirements, which became the Jan 1, 2025 statewide foam ban, are carried in the CA foam-ban entry -- cross-referenced, not double-counted, per the Oregon SB 543 convention. The recyclable-or-compostable design mandate keys to the SB 343 recyclability criteria carried under truth-in-labeling."},{"category":"single-use-plastic","law":"Single-Use Carryout Bag Ban (SB 270, 2014, upheld by Proposition 67, 2016; recast by SB 1053, 2024) + Single-Use Foodware Accessories and Standard Condiments law (AB 1884, 2018, expanded by AB 1276, 2021; Public Resources Code 42270-42273)","status":"active","effective":"Bag ban in force since 2015-2016 under SB 270/Prop 67; SB 1053 (signed Sept 22, 2024) took effect Jan 1, 2026, eliminating ALL plastic carryout bags at checkout regardless of thickness -- covered stores may provide only recycled paper bags at a minimum 10-cent charge, with the paper recycled-content floor rising to 50 percent postconsumer on Jan 1, 2028; pre-checkout produce and bulk bags must be recycled paper or certified compostable; straws-on-request at full-service restaurants since Jan 1, 2019 (AB 1884); all single-use foodware accessories and standard condiments by-request-only at all food facilities since June 1, 2022 (AB 1276), including third-party delivery platforms whose default must be no accessories","scope":"Grocery stores, large retail stores with a pharmacy, convenience stores, food marts, and liquor stores may not provide plastic carryout bags of any thickness; food facilities may not provide utensils, straws, stirrers, condiment packets, or other single-use foodware accessories unless the customer requests them, may not bundle accessories, and self-serve stations remain permitted; bag-ban penalties reach $1,000-$5,000 per day (Attorney General, district and city attorneys), while AB 1276 is locally enforced at $25 per day capped at $300 per year; correctional institutions, health care facilities, residential care facilities, and school cafeterias are excluded from the accessories law","sectors":"Grocery and covered retail stores (bags); all food facilities and third-party delivery platforms (accessories); local governments (enforcement)","source_label":"CalRecycle (carryout bag law) and California Legislature (AB 1276 chaptered text)","source_url":"https://calrecycle.ca.gov/plastics/carryoutbags/","verified":"primary","footnote":"The folded entry carries three statutes under the per-state folding rule: the bag statutes and the accessories statutes share the by-item, point-of-sale architecture. In October 2025 the Attorney General settled with four bag manufacturers ($1.7 million) over recyclability claims on thick-film bags, closing the loophole SB 1053 eliminated by statute. CalRecycle certifies reusable-bag producers but has no bag-ban enforcement authority. The state's hospitality bottle law is carried as a separate CA entry in this category (different bound sector). Distinct from SB 1335 foodware-use, SB 54 epr-packaging/foam-ban, and AB 1201/SB 343 truth-in-labeling -- no double-count."},{"category":"single-use-plastic","law":"Lodging establishments -- small plastic bottle prohibition (AB 1162, 2019; Public Resources Code Chapter 6.1, section 42372)","status":"active","effective":"Enacted Oct 9, 2019, statute effective Jan 1, 2020; prohibition in force since Jan 1, 2023 for lodging establishments with more than 50 rooms and since Jan 1, 2024 for establishments with 50 rooms or fewer","scope":"Hotels, motels, resorts, bed and breakfast inns, and vacation rentals may not provide small plastic bottles of shampoo, hair conditioner, or bath soap in sleeping rooms or shared bathrooms; bulk dispensers are encouraged and small bottles may still be provided on request outside those spaces; civil penalties of $500 for a first violation and $2,000 for subsequent violations, with a local-citation track of $500 per day capped at $2,000 annually; hospitals, nursing homes, prisons, homeless shelters, and long-term rentals are excluded","sectors":"Lodging establishments (hospitality) -- not foodservice","source_label":"California Legislature (AB 1162 chaptered text)","source_url":"https://leginfo.legislature.ca.gov/faces/billTextClient.xhtml?bill_id=201920200AB1162","verified":"primary","footnote":"HOSPITALITY-NOT-FOODWARE CAVEAT: this law binds lodging operators over toiletry bottles, not foodservice packaging -- carried for completeness of the single-use-plastic category on the MA EO 619 bottles-only precedent, and relevant to EE's hospitality ICP rather than the foodservice line. The first such state law in the nation; NY, IL, and WA followed."},{"category":"climate-disclosure","law":"SB 253 (2023) -- Climate Corporate Data Accountability Act, as amended by SB 219 (2024); Health and Safety Code section 38532","status":"active","effective":"Signed October 2023; CARB's initial implementing regulation, adopted Feb 26, 2026, sets the first-year reporting deadline -- Scope 1 and Scope 2 emissions reports (prior fiscal year data) are due Aug 10, 2026; Scope 3 reporting begins in 2027 covering fiscal-year-2026 data; limited assurance on Scope 1 and 2 is expected for 2027-2029 reporting, moving to reasonable assurance around 2030; annual program-fee determinations issue on or by Sept 10 beginning in 2026","scope":"U.S.-organized companies, public and private, with total annual revenues over $1 billion that do business in California must annually and publicly disclose greenhouse gas emissions in conformance with the GHG Protocol; revenue is measured as gross receipts using the lesser of the two prior fiscal years, and doing business in California follows Revenue and Taxation Code section 23101 on a sales-only basis; exemptions cover nonprofits, government-majority-owned entities, insurance companies (extended to SB 253 by the Feb 2026 regulation), teleworking-only entities, and wholesale-electricity-only entities; penalties up to $500,000 per reporting year","sectors":"All covered large companies across sectors -- including foodservice distributors, food management companies, grocery, hospitality, and CPG brands doing business in California; CARB administers and enforces","source_label":"California Air Resources Board (Corporate GHG Reporting and Climate-Related Financial Risk Disclosure Programs)","source_url":"https://ww2.arb.ca.gov/our-work/programs/california-corporate-greenhouse-gas-reporting-and-climate-related-financial-risk","verified":"primary","footnote":"LITIGATION FLAG: Chamber of Commerce v. Sanchez (9th Cir. No. 25-5327, appealing C.D. Cal. No. 2:24-cv-00801) challenges SB 253 and SB 261 on First Amendment grounds; the Ninth Circuit expressly declined to enjoin SB 253 (Nov 18, 2025 order), oral argument was heard Jan 9, 2026, and no decision has issued as of this pass -- SB 253 remains fully in effect and the Aug 10, 2026 first-report deadline stands. CARB's Dec 5, 2024 enforcement notice applies good-faith discretion to first-cycle reports. FOODSERVICE RELEVANCE: Scope 3 reporting (2027, fiscal-year-2026 data) makes food waste disposal and packaging procurement quantifiable, reportable line items for covered companies and their suppliers."},{"category":"climate-disclosure","law":"SB 261 (2023) -- Climate-Related Financial Risk Act, as amended by SB 219 (2024); Health and Safety Code section 38533","status":"scheduled","effective":"Signed October 2023; the initial statutory reporting deadline of Jan 1, 2026 is not in effect -- the Ninth Circuit enjoined enforcement pending appeal on Nov 18, 2025, and CARB's Dec 1, 2025 Enforcement Advisory states it will set an alternate reporting date after the appeal resolves; a voluntary public docket for early reports ran Dec 1, 2025 through July 1, 2026","scope":"U.S.-organized companies, public and private, with total annual revenues over $500 million that do business in California must publish a biennial climate-related financial risk report aligned with the TCFD framework (or IFRS S2 or an equivalent regulated framework) covering governance, strategy, risk management, and metrics and targets, posted publicly with a link submitted to CARB; the revenue, doing-business, and exemption architecture mirrors SB 253 (insurance companies statutorily exempt); penalties up to $50,000 per reporting year once enforceable","sectors":"All covered companies over the $500 million threshold across sectors; CARB administers","source_label":"California Air Resources Board (Corporate GHG Reporting and Climate-Related Financial Risk Disclosure Programs)","source_url":"https://ww2.arb.ca.gov/our-work/programs/california-corporate-greenhouse-gas-reporting-and-climate-related-financial-risk","verified":"primary","footnote":"LITIGATION FLAG and MODELING NOTE: modeled scheduled, not active, under the map's status rule -- no obligation is currently enforceable because the Ninth Circuit's Nov 18, 2025 injunction (Chamber of Commerce v. Sanchez, No. 25-5327) bars CARB from enforcing SB 261 while the appeal is pending, and CARB states that reporting is voluntary pursuant to the court order; roughly 50 companies filed voluntarily to CARB's docket. When the injunction lifts, CARB will set a new initial deadline -- a pre-flagged status re-model. The companion SB 253 emissions-reporting law was not enjoined and is carried as the active CA entry in this category."}],"municipal":[{"city":"San Francisco, CA","category":"foodware-use","law":"Food Service and Packaging Waste Reduction Ordinance (S.F. Environment Code Chapter 16; Ord. 295-06, expanded by Ord. 140-16 and 2018 amendments)","status":"active","effective":"Jun 1, 2007 (food vendors must use compostable or recyclable food service ware -- earliest major U.S. city mandate); Jan 1, 2017 (citywide sale and distribution ban on non-compostable, non-recyclable food service ware and foam); Jul 1, 2019 and Jan 1, 2020 (compostables must be fluorinated-chemical free and BPI-certified; accessories on request)","scope":"All disposable food service ware for food prepared and served in San Francisco -- containers, bowls, plates, trays, cups, lids, straws, utensils -- must be compostable (accepted in the city program; BPI-certified and fluorinated-chemical free since Jan 1, 2020, or natural-fiber items) or recyclable; polystyrene foam prohibited; applies to sale and distribution as well as use","sectors":"Restaurants, retail food vendors, City facility food providers, City departments, contractors, and lessees; the S.F. Environment Department administers","source_label":"S.F. Environment Department (Environment Code Chapter 16)","source_url":"https://www.sfenvironment.org/policy/chapter-16-food-service-waste-reduction-ordinance","verified":"primary","footnote":"The 2007 ordinance is the pioneering big-city foodware-use mandate in the U.S. Not subsumed by SB 1335, which reaches state facilities only."},{"city":"Berkeley, CA","category":"foodware-use","law":"Single Use Foodware and Litter Reduction Ordinance (Ord. 7,639-N.S., 2019; Berkeley Municipal Code Chapter 11.64)","status":"active","effective":"Mar 2019 (city facilities and city-sponsored events; accessories on request; bussing-station bins); Jan 1, 2020 (takeout only in conforming disposable foodware plus a 25-cent disposable cup charge, BMC 11.64.050); dine-in reusable foodware requirement enforced from Jul 1, 2021 after a COVID delay","scope":"Takeout food may only be served in disposable foodware accepted by Berkeley's municipal compost collection program, certified by BPI or an equivalent third party, and free of all intentionally added fluorinated chemicals; dine-in service must use reusable foodware (paper liners, wrappers, napkins, straws, and recyclable foil excepted); every disposable cup carries a mandatory 25-cent charge retained by the vendor; accessories by request only","sectors":"All prepared food vendors -- bakeries, cafeterias, restaurants, food trucks, temporary food facilities, bars, theaters, drugstores; City of Berkeley enforces (complaint-based, administrative citations)","source_label":"City of Berkeley (BMC 11.64 and Single-Use Foodware Rules)","source_url":"https://berkeleyca.gov/doing-business/operating-berkeley/food-service/single-use-foodware-rules","verified":"primary","footnote":"Widely treated as the national model ordinance: first U.S. city to combine a compostable takeout mandate, a disposable cup charge, and a dine-in reusables requirement in one law."},{"city":"Los Angeles County, CA (unincorporated areas)","category":"foodware-use","law":"Reduction of Waste from Single-Use Articles and Expanded Polystyrene Products Ordinance (adopted Apr 2022; L.A. County Code)","status":"active","effective":"May 1, 2023 (food facilities at permanent locations); Nov 1, 2023 (food trucks); May 1, 2024 (temporary food facilities such as farmers markets and events)","scope":"All single-use food service ware provided with ready-to-eat food -- containers, cups, dishes, cutlery -- must be compostable (tiered preference: PFAS and fluorinated-chemical free and home compostable or purely fiber-based; otherwise BPI plus Compost Manufacturing Alliance certified) or recyclable; full-service restaurants must use reusable food service ware for dine-in; retail sale or rental of expanded polystyrene products prohibited; street vendors exempt; hardship waivers available","sectors":"Restaurants, coffee shops, grocery and convenience stores, school and hospital cafeterias, food trucks, and temporary food facilities in unincorporated L.A. County (about 1 million residents across two-thirds of county land); violations up to 100 dollars per day, 1,000 dollars per year","source_label":"County of Los Angeles (Board of Supervisors / Chief Sustainability Office)","source_url":"https://lacounty.gov/2023/05/01/los-angeles-county-kicks-off-ordinance-for-sustainable-food-ware/","verified":"primary","footnote":"Described by the County as the largest municipality in the nation to adopt a comprehensive foodware-use mandate. The EPS retail-sale provisions overlap the foam-ban category; the statewide SB 54 EPS ban (Jan 1, 2025) now covers foam statewide, but the compostable-or-recyclable use mandate remains distinctly local."}]},"CT":{"name":"Connecticut","laws":[{"category":"organics-diversion","law":"Commercial Organics Recycling Law (CGS 22a-226e)","status":"active","effective":"Phased down 2014 -> 2020 -> 2022; universities Jan 1, 2025; K-12 July 1, 2026","scope":"At least 26 tons/year (about 0.5 ton/week). General/institutional tier has no distance limit (as of Jan 1, 2025); K-12 tier applies within 20 miles of an authorized facility (as of July 1, 2026).","sectors":"Commercial and institutions (health, education, correctional)","source_label":"CT DEEP","source_url":"https://portal.ct.gov/DEEP/Waste-Management-and-Disposal/Organics-Recycling/Commercial-Organics-Recycling-Law","verified":"primary","footnote":"The 20-mile distance limit applies to the K-12 tier (effective July 1, 2026) but was removed for the general/institutional tier (effective Jan 1, 2025, per Public Act 24-45 and the 2023 generator-definition expansion). Universities and institutions have been covered since Jan 1, 2025."},{"category":"pfas-packaging","law":"Public Act 21-191 (2021), amending the Toxics in Packaging Law (CGS 22a-255g to 22a-255m)","status":"active","effective":"Dec 31, 2023","scope":"Any food package or packaging component to which PFAS has been intentionally introduced during manufacturing or distribution, in any amount; replacement chemicals may not create a hazard as great as or greater than PFAS","sectors":"Manufacturers and distributors offering food packages for sale or promotional purposes in Connecticut","source_label":"Connecticut General Assembly","source_url":"https://www.cga.ct.gov/2021/act/Pa/pdf/2021PA-00191-R00SB-00837-PA.PDF","verified":"primary","footnote":"The same act banned PFAS Class B firefighting foam. Connecticut's broader 2024 consumer-products PFAS law adds further product categories from July 1, 2026, but food packaging was already covered by PA 21-191."},{"category":"single-use-plastic","law":"Single-use plastic checkout bag ban (Public Act 19-117, section 355; Conn. Gen. Stat. 22a-246a)","status":"active","effective":"Enacted August 2019; a 10-cent statewide fee applied Aug 1, 2019 through June 30, 2021 as the transition phase; since July 1, 2021 no owner or operator of a store may provide or sell a single-use checkout bag (plastic film under 4.0 mils)","scope":"All stores statewide; the expired transition fee was remitted to the state through the sales-tax system; paper and reusable bags remain permitted with no statewide fee, and municipalities may regulate paper bags","sectors":"Retail stores statewide","source_label":"State of Connecticut (DRS bulletin TSSB 2021-5, single-use plastic bag fee to end / ban effective)","source_url":"https://portal.ct.gov/-/media/drs/publications/tssb/tssb-2021-5.pdf","verified":"primary","footnote":"The fee-then-ban architecture makes Connecticut the cleanest example of a transition-fee sunset: the fee ended June 30, 2021, the day before the ban. Connecticut has no statewide straw, accessories, or foam statute -- its only other entries on this map are organics-diversion and pfas-packaging."}],"municipal":[]},"MA":{"name":"Massachusetts","laws":[{"category":"organics-diversion","law":"Commercial Food Material Disposal Ban (310 CMR 19.017)","status":"active","effective":"Oct 1, 2014; expanded Nov 1, 2022","scope":"More than 0.5 ton/week; no distance exemption","sectors":"Commercial and institutional (residential excluded)","source_label":"MassDEP","source_url":"https://www.mass.gov/guides/commercial-food-material-disposal-ban","verified":"primary","footnote":"No distance exemption is a key reason MassDEP data shows a significant food-waste reduction. Penalties reach $25,000 per violation."},{"category":"procurement","law":"Executive Order No. 619, Eliminating the Purchase by the Executive Department of Single-Use Plastic Bottles (Sep 21, 2023)","status":"active","effective":"Effective immediately upon signing, Sep 21, 2023; agency summaries of compliance steps were due to the Operational Services Division and the Office of Climate Innovation and Resilience by Dec 31, 2023","scope":"All executive offices and agencies must stop purchasing single-use plastic beverage bottles -- sealed rigid plastic bottles of 21 fluid ounces or less, including water, juice, milk, and soft drinks -- in favor of less harmful alternatives, and must reduce the sale or resale of such bottles on state-owned property; covered purchases now require a Single-Use Plastic Bottle Procurement Justification filing (emergency exception available); the Operational Services Division is steering statewide beverage contracts toward alternatives such as paper cartons and aluminum cans","sectors":"Massachusetts executive department offices and agencies and their statewide beverage contract vendors; eligible entities outside the executive department are encouraged but not bound","source_label":"Commonwealth of Massachusetts, Executive Order No. 619 (Mass.gov)","source_url":"https://www.mass.gov/executive-orders/no-619-eliminating-the-purchase-by-the-executive-department-of-single-use-plastic-bottles","verified":"primary","footnote":"First state procurement ban on single-use plastic bottles in the nation, per the Operational Services Division. Scope caveat: beverage bottles only -- it does not reach cups, plates, or other food service ware, so its EE relevance is as a procurement-channel market signal rather than direct foodware demand. Included under the executive-order qualification decision (binding and product-specific; disclosed as an EO, revocable by a future governor). A Senate-passed codification bill (S.3050 plastics provisions) is not enacted and is excluded under the enacted-only rule -- watch item."}],"municipal":[]},"RI":{"name":"Rhode Island","laws":[{"category":"organics-diversion","law":"R.I. Gen. Laws 23-18.9-17","status":"active","effective":"2016; education tiers added Jan 1, 2023","scope":"Tiered -- 104 tons/year general commercial; 52 tons/year higher ed; 30 tons/year K-12 -- all within 15 miles of an authorized facility","sectors":"Large commercial generators and education","source_label":"RI General Assembly","source_url":"https://webserver.rilegislature.gov/Statutes/TITLE23/23-18.9/23-18.9-17.htm","verified":"primary","footnote":"ReFED rates enforcement as weak given the distance exemption. An enforcement bill (H7342) was signed in June 2025."},{"category":"foam-ban","law":"Polystyrene Foam and Plastic Stirrers Ban (2023 legislation, SB 14)","status":"active","effective":"Jan 1, 2025","scope":"Processing, preparing, selling, or providing food or beverages in containers made in whole or in part of polystyrene foam; plastic beverage stirrers also banned","sectors":"Covered food service establishments (restaurants and similar); exempt: hospitals, nursing homes, assisted/independent living, Meals on Wheels programs, agricultural fairs, farmers markets, and food pantries or charities providing free food","source_label":"RI Department of Health","source_url":"https://health.ri.gov/sites/g/files/xkgbur1006/files/publications/guidance/styrofoam-ban-guidance.pdf","verified":"primary","footnote":"Prepackaged wholesale food items and foam coolers used for shipping or processing are outside the ban's scope."},{"category":"pfas-packaging","law":"Toxic Packaging Reduction Act amendments (H 7438A / S 2044A, 2022; R.I. Gen. Laws 23-18.13-4(d))","status":"active","effective":"Jan 1, 2025 (original Jan 1, 2024 date extended to July 31, 2024 by 2023-S0724, then to Jan 1, 2025 by 2024-S2850B)","scope":"ANY food package or packaging component applied to or in direct contact with any food or beverage -- not limited to plant fiber -- with intentionally introduced PFAS; from July 1, 2027, PFAS used as processing agents, mold release agents, or intermediates counts as intentional introduction where detected in the final package","sectors":"Manufacturers and distributors offering food packages for sale or promotional purposes in Rhode Island","source_label":"Rhode Island General Assembly (statutes)","source_url":"https://webserver.rilegislature.gov/Statutes/TITLE23/23-18.13/INDEX.htm","verified":"primary","footnote":"Rhode Island's separate PFAS in Consumer Products Ban Act of 2024 (ch. 23-18.18) covers cookware and other products from Jan 1, 2027 and is administered by RIDEM."},{"category":"single-use-plastic","law":"Plastic Waste Reduction Act (H 7065, 2022) + single-use plastic straws law (P.L. 2021, ch. 202/203; R.I. Gen. Laws ch. 21-27.2)","status":"active","effective":"Straws by-request-only at food service establishments since Jan 1, 2022; the bag ban -- passed June 2022 after a pandemic hold, with DEM regulations finalized in late 2023 -- effective Jan 1, 2024","scope":"Retail establishments including grocery stores, pharmacies, and convenience stores may not provide single-use plastic bags at the point of sale; DEM's regulations, built with the 18 of 39 municipalities that had local bans, require stitched handles for a bag to qualify as reusable -- closing the thick-film loophole; paper, reusable, and compostable-material bags remain permitted; food service establishments may provide a single-use plastic straw only on the consumer's request (self-serve plastic-straw dispensers prohibited; non-plastic straws unrestricted), enforced by the Department of Health with two written notices then $25 fines capped at $300 annually","sectors":"Retail establishments statewide (bags); food service establishments (straws)","source_label":"Rhode Island Department of Environmental Management (Plastic Waste Reduction Act)","source_url":"https://dem.ri.gov/press-releases/dem-reminds-public-plastic-waste-reduction-act-regulations-go-effect-new-year","verified":"primary","footnote":"Folded entry carrying two statutes under the per-state folding rule; the straw guidance is published by the Department of Health, the second enforcing agency. Rhode Island's plastic STIRRER ban is a provision of SB 14 (2023) and remains modeled in the RI foam-ban entry -- cross-referenced one-way here rather than double-counted."}],"municipal":[]},"VT":{"name":"Vermont","laws":[{"category":"organics-diversion","law":"Universal Recycling Law (Act 148, 2012)","status":"active","effective":"Food scrap ban fully in effect July 1, 2020","scope":"All generators including residential -- no threshold (the most comprehensive ban)","sectors":"Commercial and residential","source_label":"VT DEC","source_url":"https://dec.vermont.gov/waste-management/solid/universal-recycling","verified":"primary"},{"category":"foam-ban","law":"Single-Use Products Law (Act 69 of 2019)","status":"active","effective":"July 1, 2020","scope":"Expanded polystyrene food and beverage containers (part of a broader law also covering plastic bags, stirrers, and straws-on-request)","sectors":"Stores and food service establishments","source_label":"VT DEC","source_url":"https://dec.vermont.gov/waste-management/solid/materials-mgmt/single-use-products-law","verified":"primary","footnote":"Some secondary summaries list a 2021 effective date; VT DEC (primary) confirms the Act 69 bans took effect July 1, 2020. The same statute's carryout bag, straw, and stirrer provisions are carried under single-use-plastic per the Oregon SB 543 convention, cross-referenced rather than double-counted."},{"category":"pfas-packaging","law":"Act 36 (S.20, 2021), 18 V.S.A. ch. 33A; recodified by Act 131 (2024) at 9 V.S.A. section 2494z","status":"active","effective":"July 1, 2023; recodified under the Consumer Protection Title effective Jan 1, 2026 (ban continuous throughout)","scope":"All food packages and packaging components intended for direct food contact -- not limited to plant fiber -- with intentionally added PFAS in any amount; ortho-phthalates also banned; bisphenols restrictable by Health Department rule","sectors":"Manufacturers, suppliers, and distributors; Attorney General enforces under the Consumer Protection Act","source_label":"Vermont Attorney General","source_url":"https://ago.vermont.gov/sites/ago/files/Guidance%20on%20PFAS%20Product%20Bans%20(2025).pdf","verified":"primary","footnote":"MODELING NOTE: the original 18 V.S.A. ch. 33A was repealed effective Jan 1, 2026 and the food-packaging ban now lives at 9 V.S.A. 2494z (Act 131 of 2024). Citations to chapter 33A alone are outdated -- several secondary trackers still use them."},{"category":"single-use-plastic","law":"Single-Use Products Law (Act 69 of 2019; 10 V.S.A. sections 6691-6700) -- carryout bag, straw, and stirrer provisions","status":"active","effective":"Effective July 1, 2020 for all provisions","scope":"Stores and food service establishments may not provide plastic carryout bags of any type at checkout -- including thick-film and compostable plastic bags; recycled paper carryout bags may be provided at a minimum 10-cent charge retained by the business; food service establishments may provide single-use plastic straws only on request (hospitals, nursing homes, and other care facilities exempt; non-plastic straws may be offered freely but compostable-plastic straws count as plastic); single-use plastic stirrers are banned outright with no on-request option","sectors":"Stores (grocery, supermarket, convenience, liquor, drycleaner, pharmacy, and other retail) and food service establishments statewide","source_label":"Vermont Department of Environmental Conservation (Single-Use Products Law)","source_url":"https://dec.vermont.gov/waste-management/solid/materials-mgmt/single-use-products-law","verified":"primary","footnote":"Same statute as the VT foam-ban entry (Oregon SB 543 convention) -- the expanded polystyrene provisions (10 V.S.A. 6696) remain modeled there; the bag (6692-6693), straw (6694), and stirrer (6695) provisions are carried here, cross-referenced rather than double-counted. The stirrer ban is one of only two outright statewide plastic-item bans in this category (with Honolulu's municipal ordinance); most states use by-request models."}],"municipal":[]},"NJ":{"name":"New Jersey","laws":[{"category":"organics-diversion","law":"Food Waste Recycling Law (P.L. 2020, c.24)","status":"active","effective":"Requirements began October 2021","scope":"At least 52 tons/year projected, within 25 road miles of an authorized facility","sectors":"Broad large commercial generators -- includes restaurants, supermarkets, hospitals, casinos, and institutions","source_label":"NJDEP","source_url":"https://dep.nj.gov/dshw/swpl/fw/food-waste-recycling-rules/","verified":"primary"},{"category":"foam-ban","law":"Get Past Plastic Law (P.L. 2020, c.117)","status":"active","effective":"May 4, 2022","scope":"Sale or provision of polystyrene foam food service products -- containers, plates, hot/cold cups, meat and vegetable trays, cutlery, egg cartons","sectors":"All stores, grocery stores, and food service businesses statewide (restaurants, delis, food trucks, cafeterias)","source_label":"NJDEP","source_url":"https://dep.nj.gov/get-past-plastic/","verified":"primary","footnote":"Exemptions (raw meat/fish trays, manufacturer-prepackaged foods, small portion cups, and health/safety use in hospitals, nursing homes, and correctional facilities) run until May 4, 2027 unless extended by DEP. Penalties: warning, then up to $1,000/day, then up to $5,000/day. The same statute's carryout bag ban and plastic-straws-by-request provisions are carried under single-use-plastic per the Oregon SB 543 convention, cross-referenced rather than double-counted."},{"category":"pfas-packaging","law":"Protecting Against Forever Chemicals Act (S1042 / A1421; P.L. 2025, c.202, signed Jan 12, 2026)","status":"scheduled","effective":"Jan 12, 2028 (chapter law: act took effect immediately on Jan 12, 2026 approval, and the food-packaging prohibition begins two years after the effective date). One secondary (Morgan Lewis) computes Jan 13, 2028; the plain two-years-after reading and other secondaries give Jan 12","scope":"Fiber-based food packaging with intentionally added PFAS, alongside cosmetics, carpets, and fabric treatments; PFAS-containing cookware must carry a bilingual disclosure label; technically unavoidable trace quantities from impurities or manufacturing are exempt","sectors":"Sale, offer for sale, or distribution for sale in New Jersey; NJDEP must establish a PFAS source-reduction program by Jan 12, 2027","source_label":"NJ Legislature (P.L. 2025, c.202 chaptered law)","source_url":"https://pub.njleg.state.nj.us/Bills/2024/AL25/202_.PDF","verified":"primary","footnote":"Codified at C.56:3-53 to 56:3-63; consumer-product prohibitions (sections 1-11) are enforced by the Division of Consumer Affairs, while NJDEP runs the source-reduction program (due Jan 12, 2027) under sections 12-14. Primary source verified against the chaptered law on this pass."},{"category":"single-use-plastic","law":"Get Past Plastic Law (P.L. 2020, c.117) -- single-use carryout bag ban and plastic-straws-by-request provisions (C.13:1E-99.126 et al.)","status":"active","effective":"Signed Nov 4, 2020; plastic straws by-request-only at food service businesses since Nov 4, 2021; since May 4, 2022 no store or food service business may provide or sell single-use plastic carryout bags regardless of thickness, and grocery stores of 2,500 square feet or more may not provide single-use PAPER carryout bags either -- reusable bags only","scope":"Stores (grocery, convenience, liquor, pharmacy, and other retail) and food service businesses (restaurants, cafes, food trucks, movie theaters, and institutional cafeterias); the paper-bag prohibition at large groceries is unique among the states on this map; exempt bags include loose-produce, live-animal, laundry, newspaper, and prescription bags; penalties run warning, then up to $1,000 per day, then up to $5,000 per day, enforced by DEP, municipalities, and county environmental health agencies -- except the straw provision, which the Department of Health enforces with municipalities","sectors":"Retail stores, grocery stores, and food service businesses statewide","source_label":"New Jersey Department of Environmental Protection (Get Past Plastic)","source_url":"https://dep.nj.gov/get-past-plastic/","verified":"primary","footnote":"Same statute as the NJ foam-ban entry (Oregon SB 543 convention) -- the polystyrene provisions remain modeled there; the bag and straw provisions are carried here, cross-referenced rather than double-counted. The nation's only statewide ban on paper carryout bags at large groceries. The 2026 Skip the Stuff utensils law is carried as a separate scheduled NJ entry in this category."},{"category":"single-use-plastic","law":"Skip the Stuff Law (S-3195 / A-5157, signed Jan 20, 2026, amending P.L. 2002, c.128 and P.L. 2020, c.117)","status":"scheduled","effective":"Takes effect Aug 1, 2026; bundled utensil-or-condiment packages containing more than one item type are prohibited from Aug 1, 2027; food service businesses located in food courts are exempt until Aug 1, 2028","scope":"Food service businesses -- including restaurants, cafes, food trucks, vendor stations, arenas, and cafeterias -- may provide single-use utensils and condiments only on the customer's express request across dine-in, takeout, delivery, and drive-through; full-service restaurants with on-site seating for 10 or more must provide reusable, washable utensils to dine-in customers; online ordering platforms must default to no utensils or condiments; single-use portion cups for sauces and self-serve condiment stations remain permitted; K-12 schools, licensed health care facilities, and correctional facilities are exempt; DEP must run a 180-day education campaign before enforcement, with penalties beginning at a warning and escalating for repeat violations","sectors":"Food service businesses and online ordering platforms statewide","source_label":"New Jersey Department of Environmental Protection (Get Past Plastic -- utensils and condiments provisions)","source_url":"https://dep.nj.gov/get-past-plastic/","verified":"primary","footnote":"Modeled scheduled under the enacted-with-future-date convention: signed in the final hours of the Murphy administration on Jan 20, 2026 but effective Aug 1, 2026. Described by the National Caucus of Environmental Legislators as the most comprehensive skip-the-stuff law in the country because of the dine-in reusable-utensil mandate. Post-passage secondary sources conflict on the exact penalty amounts, so figures are omitted pending the chapter law -- flagged for verification. A modeling exception (NJ x2 in this category): kept separate from the c.117 entry because its status differs."}],"municipal":[]},"NY":{"name":"New York","laws":[{"category":"organics-diversion","law":"Food Donation & Food Scraps Recycling Law (ECL Art. 27, Title 22)","status":"active","effective":"Jan 1, 2022; expands Jan 1, 2027 and Jan 1, 2029","scope":"At least 2 tons/week (annual average), within 25 miles of an organics recycler (current through 2026)","sectors":"Commercial and institutional","source_label":"NYSDEC","source_url":"https://dec.ny.gov/environmental-protection/recycling-composting/organic-materials-management/food-donation-scraps-recycling-law","verified":"primary","footnote":"Threshold drops to 1 ton/week within 50 miles on Jan 1, 2027, and 0.5 ton/week on Jan 1, 2029. Hospitals, K-12 schools, nursing homes, and adult care facilities are exempt. New York City is exempt -- it has its own local law.","carveout":"Excludes New York City (NYC runs its own local law)"},{"category":"foam-ban","law":"Expanded Polystyrene Foam Container and Loose Fill Packaging Ban (ECL Art. 27, Title 30, enacted 2020)","status":"active","effective":"Jan 1, 2022; expanded Jan 1, 2026 to non-encapsulated EPS cold-storage containers (coolers, ice chests)","scope":"Single-use EPS food service containers (bowls, cartons, clamshells, cups, lids, plates, trays) and polystyrene loose fill packaging; cold-storage EPS containers added Jan 1, 2026","sectors":"Covered food service providers (restaurants, caterers, mobile vendors, retail food stores, schools, colleges), plus manufacturers and stores selling into New York","source_label":"NYSDEC","source_url":"https://dec.ny.gov/environmental-protection/recycling-composting/go-foam-free","verified":"primary","carveout":"Excludes New York City (NYC enforces its own earlier local ban)","footnote":"Financial hardship waivers available to qualifying providers. NYSDEC describes this as the nation's strongest state EPS ban at adoption."},{"category":"pfas-packaging","law":"PFAS in Food Packaging Ban (S8817, 2020; ECL Article 37, Title 2, section 37-0209 -- Hazardous Packaging Act)","status":"active","effective":"Dec 31, 2022","scope":"Food packaging intended for direct food contact and comprised in substantial part of paper, paperboard, or other plant-fiber materials, with intentionally added PFAS","sectors":"Anyone distributing, selling, or offering for sale food packaging in New York, including retailers and food service establishments; compliance certifications must be produced to DEC on request","source_label":"NYSDEC","source_url":"https://dec.ny.gov/environmental-protection/recycling-composting/businesses/pfas-in-food-packaging","verified":"primary","footnote":"Applies to intentionally added PFAS only; PFAS introduced as processing aids are not prohibited, though DEC encourages manufacturers to avoid them."},{"category":"procurement","law":"Executive Order 22, Leading by Example: Directing State Agencies to Adopt a Sustainability and Decarbonization Program (2022), implemented through the GreenNY Food Service Ware purchasing specification (approved Dec 11, 2025)","status":"active","effective":"EO 22 signed Sep 2022, superseding EO 4 (2008) and related orders; affected entities must follow approved GreenNY specifications when procuring under existing contracts and in new solicitations; the consolidated Food Service Ware specification was approved Dec 11, 2025; the EO 22 single-use plastics directive phases out plastic food service products, utensils, straws, stirrers, and wraps and packaging film on product-specific deadlines","scope":"State agencies, public authorities, and public benefit corporations must purchase food service ware meeting GreenNY specifications: reusable food service ware is preferred, and single-use food service ware must be certified compostable (Biodegradable Products Institute, Compost Manufacturing Alliance, or a state-approved equivalent) because non-compostable single-use food service ware is not GreenNY compliant under the EO 22 directive to eliminate single-use plastics; GreenNY sample contract language carries the state PFAS-in-food-packaging prohibition (ECL 37-0209) into vendor contracts; a formal exemption process covers form-function-utility, cost-competitiveness, and public-health-or-safety grounds","sectors":"All affected entities -- executive state agencies, public authorities, and public benefit corporations, including SUNY campuses -- and vendors supplying food service ware under state contracts; the GreenNY Council (OGS, DEC, DOH and others) administers","source_label":"NYS Office of General Services (GreenNY Food Service Ware specification) and Executive Order 22","source_url":"https://ogs.ny.gov/greenny/food-service-ware","verified":"primary","footnote":"Modeled under this pass's executive-order qualification decision: EO 22 is an in-force executive order, not a statute -- binding on agency purchasing with a formal exemption process, but revocable by a future governor. It qualifies because the GreenNY specification specifically binds food service ware purchases; generic percent-spend EPP orders in other states do not. Distinct from New York's statewide foam ban and organics law already on the map; the state foam ban binds all covered food service providers directly, while this order governs what the state itself buys."},{"category":"single-use-plastic","law":"Bag Waste Reduction Act (ECL Article 27, Title 28, enacted April 2019)","status":"active","effective":"Effective March 1, 2020; enforcement began Oct 19, 2020 after the state court's Aug 20, 2020 decision in the Poly-Pak Industries challenge upheld the law and most of the Part 351 regulations","scope":"Any person required to collect New York State sales tax may not distribute plastic carryout bags of ANY thickness -- New York uniquely allows no thick-film reusable plastic bag; reusable checkout bags cannot be made of film plastic at all; exempt bags include produce and bulk-item bags, prescription bags, garment bags, and plastic carryout bags provided by restaurants and similar food service establishments for carryout or delivery; cities and counties may opt in to a 5-cent paper-bag reduction fee (SNAP and WIC customers exempt); penalties run warning, then $250, then $500 per violation in the same calendar year","sectors":"All sales-tax vendors statewide; restaurants are exempt for carryout and delivery bags","source_label":"New York State Department of Environmental Conservation (Bag Waste Reduction Act)","source_url":"https://dec.ny.gov/environmental-protection/recycling-composting/bag-waste-reduction-law","verified":"primary","footnote":"The Aug 20, 2020 Poly-Pak decision also invalidated two regulatory exemptions for non-film plastic reusable bags (6 NYCRR 351-1.2(f)(11) and (n)) -- the surviving rule is stricter than most states'. The restaurant carryout-bag exemption is a direct foodservice-relevance point. New York's hospitality bottle law is carried as a separate NY entry in this category. Distinct from the NY foam ban, EO 22 procurement entry, and organics law -- no double-count."},{"category":"single-use-plastic","law":"Small Plastic Bottle Hospitality Personal Care Product Restrictions Law (signed 2021)","status":"active","effective":"In force since Jan 1, 2025 for hotels, apartment hotels, motels, and boarding houses with more than 50 rooms, and since Jan 1, 2026 for all such lodging regardless of size","scope":"Lodging may not provide small plastic bottles containing less than 12 ounces of a hospitality personal care product (any product for cleansing, conditioning, or moisturizing the body); violations draw a warning notice with 30 days to correct, then $250 for the first post-warning violation and $500 for each subsequent violation in the same calendar year, with penalties credited to the Environmental Protection Fund","sectors":"Hotels, apartment hotels, motels, and boarding houses (hospitality) -- not foodservice","source_label":"New York State Department of Environmental Conservation (small plastic hospitality bottles)","source_url":"https://dec.ny.gov/environmental-protection/recycling-composting/small-plastic-hospitality-bottles","verified":"primary","footnote":"HOSPITALITY-NOT-FOODWARE CAVEAT: binds lodging operators over toiletry bottles, not foodservice packaging (MA EO 619 bottles-only precedent). The 12-ounce threshold is double California's practical scope and the broadest product definition of the four state hospitality laws. DEC's Dec 2025 reminder pairing this law's small-hotel phase with the foam ban's Jan 1, 2026 cold-storage-container expansion is logged as a foam-ban category watch item, not modeled here."}],"municipal":[{"city":"New York City, NY","category":"foam-ban","law":"Local Law 142 of 2013 -- EPS Foam Ban","status":"active","effective":"Jan 1, 2019 (fines began July 1, 2019 after a warning period)","scope":"Possessing, selling, or offering single-service EPS foam food service articles (cups, bowls, plates, trays, clamshells) and loose fill packaging","sectors":"Food service establishments, mobile food commissaries, stores, and foam manufacturers/distributors operating in the five boroughs","source_label":"NYC DSNY","source_url":"https://www.nyc.gov/site/dsny/businesses/materials-handling/foam-containers.page","verified":"primary","footnote":"Predates and is preserved by the statewide ban, which exempts NYC. Hardship waivers available for nonprofits and small businesses under $500K revenue. Exempt: prepackaged sealed foam containers and raw-protein butcher-case foam."}]},"MD":{"name":"Maryland","laws":[{"category":"organics-diversion","law":"HB 264 (2021) -- Organics Recycling & Waste Diversion (COMAR 26.04.13)","status":"active","effective":"At least 2 tons/week began 2023; at least 1 ton/week began 2024","scope":"At least 1 ton/week, within 30 miles of an organics recycling facility","sectors":"Commercial and institutional -- schools, supermarkets, and institutional cafeterias covered","source_label":"MDE","source_url":"https://mde.maryland.gov/programs/land/RecyclingandOperationsprogram/Pages/Solid-Waste-Management---Organics-Recycling-and-Waste-Diversion---Food-Residuals.aspx","verified":"primary","footnote":"MDE frames this as a diversion mandate, not a disposal ban. Restaurants with dining rooms are excluded."},{"category":"foam-ban","law":"Expanded Polystyrene Food Service Products Ban (HB 109, 2019)","status":"active","effective":"Oct 1, 2020 (first state ban to take effect)","scope":"EPS food service products -- single-use foam containers, cups, plates, and trays","sectors":"Food service businesses including public and private schools (K-12 and higher ed) and government-run food service; also manufacturers, distributors, and retailers","source_label":"Maryland MDE","source_url":"https://mde.maryland.gov/programs/land/RecyclingandOperationsprogram/Pages/Expanded-Polystyrene-Food-Service-Products-Ban.aspx","verified":"primary","footnote":"Exemptions include egg cartons shipped into Maryland, EPS used for raw meats, and food prepackaged in EPS before receipt by a Maryland food service business."},{"category":"pfas-packaging","law":"George Walter Taylor Act (SB 273 / HB 275, 2022)","status":"active","effective":"Jan 1, 2024","scope":"Food packages and packaging components designed for direct food contact and composed in substantial part of plant fibers, plus plastic disposable gloves used in commercial or institutional food service, with intentionally added PFAS","sectors":"Manufacturers and distributors; certificates of compliance must be produced to MDE within 30 days of request","source_label":"Maryland MDE","source_url":"https://mde.maryland.gov/programs/land/Documents/SWP/PFAS%20Posts/Restrictions%20on%20PFAS%20Sale%20and%20Use%20in%20Maryland.pdf","verified":"primary","footnote":"Named for a Maryland firefighter who died of occupational cancer linked to PFAS exposure. The same act restricts PFAS firefighting foam and rugs/carpets."},{"category":"truth-in-labeling","law":"Compostable, Degradable, and Biodegradable Plastic Products -- Labeling (HB 1349, 2017; Chapter 374; Md. Code, Environment 9-2101 to 9-2106)","status":"active","effective":"Oct 1, 2017 (act); sale prohibitions operative Oct 1, 2018","scope":"Plastic products may not be sold labeled as biodegradable, degradable, or decomposable, subject to limited exceptions; products labeled compostable must meet ASTM D6400 or D6868 and FTC Green Guides labeling requirements; home compostable claims require the OK Compost Home certification standard (Vincotte); compostable bags may not simultaneously be marketed as recyclable; separate biodegradability standards apply to agricultural mulch films","sectors":"Any person selling covered plastic products in Maryland; penalties apply for knowing violations","source_label":"Maryland General Assembly (Ch. 374 of 2017, chaptered law)","source_url":"https://mgaleg.maryland.gov/2017RS/chapters_noln/Ch_374_hb1349T.pdf","verified":"primary","footnote":"Modeled on the US Composting Council model compostable labeling legislation, itself based on California law -- one of the earliest state compostable-labeling statutes."},{"category":"epr-packaging","law":"Packaging and Paper Products -- Producer Responsibility Plans (SB 901, Chapter 431 of 2025; Md. Code, Environment 9-2501 et seq.), building on the SB 222 (2023) framework act","status":"active","effective":"Signed May 13, 2025; first implementing regulations (COMAR 26.04.14, registration-focused) effective May 25, 2026; producer registration and simplified calendar-year-2025 supply reporting to the PRO were due May 31, 2026, ahead of the PRO's July 1, 2026 registration filing with MDE; from July 1, 2026 producers must join a PRO, comply individually, or operate an approved alternative collection program; producer responsibility plans due July 1, 2028; from Oct 29, 2028 covered materials may not be sold, offered for sale, distributed, or imported without an approved plan on file; local-government cost reimbursement rises from 50 percent in 2028 to 90 percent by 2030","scope":"Producers of packaging and paper products sold, offered for sale, imported, or distributed in Maryland -- including service packaging such as carry-out bags, take-out and home-delivery food service packaging, and beverage containers under 5 liters; Circular Action Alliance is the approved PRO, and MDE's registration categories include certified compostable food service ware, which carries specific labeling requirements to register under that category; de minimis exemption for under one ton of covered material or under $2 million in global gross revenue; fees are eco-modulated toward recyclable, reusable, and compostable design","sectors":"Producers -- manufacturers, brand owners, first sellers, first distributors, or shippers under the statutory hierarchy -- of packaging and paper products in Maryland commerce","source_label":"Maryland Department of the Environment","source_url":"https://mde.maryland.gov/programs/land/WasteManagement/Pages/ProducerResponsibility.aspx","verified":"primary","footnote":"Maryland uniquely permits additional PROs to register from July 1, 2026 rather than mandating a single PRO for the first plan period. MDE has stated that further rulemakings will follow the initial registration-focused regulations."}],"municipal":[]},"WA":{"name":"Washington","laws":[{"category":"organics-diversion","law":"Organics Management Law (HB 1799, 2022)","status":"active","effective":"Jan 1, 2025 (at least 4 cu yd/week); Jan 1, 2026 (at least 96 gal/week); penalties began July 1, 2026","scope":"Back-of-house organics separation at the threshold volume","sectors":"Commercial businesses","source_label":"WA Dept. of Ecology","source_url":"https://ecology.wa.gov/waste-toxics/reducing-recycling-waste/organics-and-food-waste/2022-organics-management-law","verified":"primary","footnote":"Applies only within designated Business Organics Management Areas (BOMAs), set annually by Ecology across specific zip codes and counties -- not statewide. Businesses outside a BOMA are not covered."},{"category":"foam-ban","law":"SB 5022 (2021) -- Expanded Polystyrene Restrictions","status":"active","effective":"Packing peanuts June 1, 2023; food service products and portable coolers June 1, 2024","scope":"Sale and distribution of EPS food service products (containers, plates, bowls, clamshells, trays, cups) and portable coolers; no sell-through allowance for previously purchased stock","sectors":"Any person, firm, corporation, government entity, or organization selling or distributing covered EPS products","source_label":"WA Dept. of Ecology","source_url":"https://ecology.wa.gov/waste-toxics/reducing-recycling-waste/plastics/2021-plastic-pollution-laws/expanded-polystyrene-ban","verified":"primary","footnote":"Exempt: trays/packaging for raw or butchered meat, fish, poultry, seafood, produce, and eggs; EPS for drugs, medical devices, and perishable-commodity shipping. Ecology enforces first via education and technical assistance. The same statute's food-service-products-on-request provision is carried under single-use-plastic per the Oregon SB 543 convention, cross-referenced rather than double-counted."},{"category":"pfas-packaging","law":"Healthy Food Packaging Act (ESHB 2658, 2018; RCW 70A.222.070)","status":"active","effective":"Feb 1, 2023 (wraps and liners, plates, food boats, pizza boxes); May 1, 2024 (bags and sleeves, bowls, flat serviceware, open-top containers, closed containers)","scope":"Intentionally added PFAS in plant-fiber food packaging, phased in category by category as Ecology confirms safer alternatives through peer-reviewed alternatives assessments","sectors":"Food packaging manufacturers, distributors, and retailers; manufacturers must keep a certificate of compliance on file for three years after last sale","source_label":"WA Dept. of Ecology","source_url":"https://ecology.wa.gov/waste-toxics/reducing-toxic-chemicals/washingtons-toxics-in-products-laws/pfas-in-food-packaging","verified":"primary","footnote":"First state to legislate PFAS out of food packaging (2018). The ban only reaches categories where Ecology has formally found safer alternatives, so future assessments can add more."},{"category":"truth-in-labeling","law":"Plastic Product Degradability Act (HB 1569, 2019; RCW chapter 70A.455), expanded by the 2022 organics management law (HB 1799, chapter 180)","status":"active","effective":"Jul 1, 2020 (original standards); Jan 1, 2024 (expanded third-party certification and color and labeling requirements under the 2022 amendments)","scope":"Products labeled compostable must meet ASTM D6400 or D6868 (D8410, ISO 17088, EN 13432, or equivalents for some product types), carry a third-party certifier logo, the word compostable where possible, and green, beige, or brown color signaling; products made only of wood or greater than 98 percent fiber with no plastic or wax additives or coatings are exempt; biodegradable, degradable, and decomposable terms are prohibited on plastic products; noncompostable products may not use compostable-style tinting or color schemes; producers file declarations of compliance with Ecology","sectors":"Producers, sellers, and distributors of plastic products into Washington; Ecology and cities and counties have concurrent enforcement with escalating penalties of up to 2,000, 5,000, and 10,000 dollars per violation","source_label":"WA Dept. of Ecology (compostable product labeling)","source_url":"https://ecology.wa.gov/waste-toxics/reducing-recycling-waste/plastics/compost-labeling","verified":"primary","footnote":"The greater-than-98-percent-fiber exemption is directly relevant to plant-fiber products with no plastic coatings. Home compostable claims additionally require industrial-setting certification plus reproducible scientific evidence consistent with FTC guides."},{"category":"epr-packaging","law":"Recycling Reform Act (E2SSB 5284, signed May 17, 2025; chapter 70A.208 RCW)","status":"active","effective":"Law effective July 27, 2025; producers were required to appoint a PRO by Jan 1, 2026; the PRO registered with Ecology by March 1, 2026 (Ecology announced Circular Action Alliance March 4, 2026); producers must be members of a registered PRO or register individually by July 1, 2026; simplified calendar-year-2025 supply reports were due to the PRO May 31, 2026; statewide collection lists due Oct 1, 2026 and preliminary needs assessment due Dec 31, 2026; PRO program plan due Oct 1, 2028; from March 1, 2029 unregistered producers may not introduce covered materials and Ecology enforcement begins; full program operation with at least 90 percent service-provider reimbursement from Jan 1, 2030, when curbside recycling becomes mandatory wherever curbside garbage collection exists","scope":"Producers of residential packaging and paper products introduced into Washington, including service packaging that protects, contains, transports, serves, or facilitates delivery of consumer products; civil penalties up to $1,000 per violation per day, rising to $10,000 for repeat violations; exclusions include packaging for hazardous or flammable products and paint-stewardship containers","sectors":"Producers -- item manufacturers, brand owners or licensees, importers of record, or Washington distributors under the statutory hierarchy -- of residential packaging and paper products","source_label":"Washington State Department of Ecology (Recycling Reform Act)","source_url":"https://ecology.wa.gov/waste-toxics/reducing-recycling-waste/our-recycling-programs/recycling-reform-act","verified":"primary","footnote":"The seventh and newest enacted state program. Distinct from the three Washington statutes already on the map (RCW 70A.222 pfas-packaging, RCW 70A.455 truth-in-labeling, SB 5022 foam ban) and from the DES food service ware purchasing specifications excluded in the procurement pass -- no double-count."},{"category":"single-use-plastic","law":"Plastic bag ban (SB 5323, 2020; chapter 70A.530 RCW) + food service products on request (SB 5022, 2021; chapter 70A.245 RCW)","status":"active","effective":"Bag ban in force since Oct 1, 2021; accessories-on-request in force since Jan 1, 2022; since Jan 1, 2026 the pass-through charge for thick-film reusable plastic bags rose from 8 to 12 cents (paper stays at 8 cents), with an additional 4-cent penalty charge on 4-mil plastic film bags from Jan 1, 2026 through Dec 31, 2027; the minimum reusable-film thickness rises from 2.25 mils to 4 mils on Jan 1, 2028","scope":"All retail and grocery stores, restaurants, takeout establishments, festivals, and markets may not provide single-use plastic carryout bags; compliant paper bags (40 percent postconsumer content or wheat straw, labeled) carry an 8-cent charge and thick-film reusable plastic bags a 12-cent charge, both waived for food-assistance customers; food service businesses may provide single-use utensils, straws, condiment packaging, and cold-beverage cup lids only on customer request -- the first state to extend on-request beyond straws -- including through third-party delivery platforms, with hot-beverage lids and drive-through or delivery items excepted","sectors":"Retail and grocery stores, restaurants, and food service businesses statewide, including third-party delivery platforms","source_label":"Washington State Department of Ecology (plastic bag ban)","source_url":"https://ecology.wa.gov/waste-toxics/reducing-recycling-waste/plastics/plastic-bag-ban","verified":"primary","footnote":"Folded entry carrying two statutes under the per-state folding rule. SB 5022 is the same statute as the WA foam-ban entry (Oregon SB 543 convention) -- the EPS provisions remain modeled there and the accessories-on-request provision is carried here, cross-referenced rather than double-counted; SB 5022's recycled-content mandates stay outside this map's scope (parked category 9). The Jan 1, 2026 charge escalation and 2028 4-mil floor are the nation's only legislated thick-film phase-down. WA's lodging toiletries law is carried as a separate scheduled WA entry. Distinct from 70A.222 pfas-packaging, 70A.455 truth-in-labeling, and 70A.208 epr-packaging -- no double-count."},{"category":"single-use-plastic","law":"Plastic health and beauty product container restrictions for lodging (HB 1085, 2023)","status":"scheduled","effective":"Signed April 20, 2023; the lodging restrictions take effect Jan 1, 2027 for establishments with 50 or more units and Jan 1, 2028 for establishments with fewer than 50 units","scope":"Lodging establishments -- hotels, motels, resorts, inns, timeshares, short-term rentals, and vacation rentals, but not hospitals, nursing homes, or retirement communities -- may not provide shampoo, hair conditioner, hand or bath soap, body wash, shower gel, lotion, or hand sanitizer in plastic containers under 6 ounces, plastic wrappers, or other single-use plastic packaging; refillable bulk dispensers are unrestricted and restricted products may be provided on request; Ecology enforces on a complaint basis with civil penalties up to $500 per day capped at $2,000 annually per establishment, appealable to the Pollution Control Hearings Board","sectors":"Lodging establishments (hospitality) -- not foodservice","source_label":"Washington State Legislature (SHB 1085 Senate bill report)","source_url":"https://lawfilesext.leg.wa.gov/biennium/2023-24/Pdf/Bill%20Reports/Senate/1085-S%20SBR%20WM%20OC%2023.pdf","verified":"primary","footnote":"HOSPITALITY-NOT-FOODWARE CAVEAT: binds lodging operators over toiletry packaging, not foodservice (MA EO 619 bottles-only precedent). Modeled scheduled under the enacted-with-future-date convention -- no lodging obligation is enforceable before Jan 1, 2027. STALE-SECONDARY NOTE: several advocacy summaries cite 2024/2025 effective dates from early bill versions; the official Senate Bill Report controls (2027/2028). HB 1085's foam-dock and bottle-filling-station provisions bind construction and overwater structures, outside this map's scope. Broadest product list of the four state hospitality laws (includes wrappers and hand sanitizer)."}],"municipal":[{"city":"Seattle, WA","category":"foodware-use","law":"Seattle food packaging requirements (Seattle Municipal Code 21.36.086; Director's Rule SW-500)","status":"active","effective":"Jul 1, 2010 (all single-use food service packaging must be compostable or recyclable, with collection bins and services required); Jul 1, 2018 (plastic straws and utensils exemption expired -- compostable or reusable required); Jul 1, 2023 (plastic and plastic-coated paper portion cups prohibited; non-compostable plastic-coated brown paper packaging prohibited under Director's Rule SW-500)","scope":"Single-use food service packaging and serviceware -- plates, bowls, boats, trays, clamshells, containers, cups, straws, utensils -- must be compostable or recyclable in Seattle's programs; on-premises dining requires reusable serviceware or approved compostable items; businesses with customer disposal stations must provide labeled compost and recycling bins and arrange collection service","sectors":"All food service businesses -- restaurants, grocery stores, delis, coffee shops, food trucks, institutional cafeterias, and event food vendors; Seattle Public Utilities inspects and enforces","source_label":"Seattle Public Utilities (food service packaging requirements)","source_url":"https://www.seattle.gov/utilities/your-services/collection-and-disposal/food-and-yard/business-and-commercial-compostables/food-packaging-requirements","verified":"primary","footnote":"One of the earliest citywide foodware-use mandates (2010). Not subsumed: Washington's statewide laws (labeling under RCW 70A.455, accessories-on-request under RCW 70A.245, foam ban) contain no statewide compostable-or-recyclable use requirement."}]},"NH":{"name":"New Hampshire","laws":[{"category":"organics-diversion","law":"HB 300 (2023), RSA 149-M:27","status":"active","effective":"Feb 1, 2025","scope":"At least 1 ton/week, within 20 miles of an authorized facility","sectors":"Commercial generators (institutions, restaurants, grocery stores)","source_label":"NHDES","source_url":"https://www.des.nh.gov/waste/solid-waste/waste-reduction-and-diversion","verified":"primary"},{"category":"pfas-packaging","law":"HB 1649 (2024) -- RSA 149-M:64, Consumer Products PFAS Use Restricted","status":"scheduled","effective":"Jan 1, 2027","scope":"Food packaging and containers, among multiple consumer product categories, with intentionally added PFAS; exemptions include second-hand products and products with at least 85 percent recycled content","sectors":"Sale, offer for sale, or distribution for sale or promotional purposes in New Hampshire; certificates of compliance furnished to NHDES on request","source_label":"NH Dept. of Environmental Services","source_url":"https://www.pfas.des.nh.gov/pfas-products/pfas-consumer-products","verified":"primary","footnote":"A 2025 amendment added ski, boat, and surfboard waxes to the banned categories. NHDES reports to the governor and legislature on implementation every three years."}],"municipal":[]},"IL":{"name":"Illinois","laws":[{"category":"organics-diversion","law":"Large Event Facilities Act (SB 2876, 2024)","status":"active","effective":"Jan 1, 2025","scope":"Event facilities with legal occupancy of at least 3,500 must provide recycling and composting bins (not tonnage-based)","sectors":"Large venues only (stadiums, convention centers)","source_label":"Illinois General Assembly","source_url":"https://www.ilga.gov/legislation/ilcs/ilcs3.asp?ActID=4544&ChapterID=36","verified":"primary","footnote":"Illinois's enacted law is scoped to large event venues (3,500+ capacity), not a tonnage-based commercial generator mandate like the other active states. A broader generator bill (SB 1398) is pending, not enacted.","venueOnly":true},{"category":"procurement","law":"Illinois Procurement Code single-use plastics prohibition and preference (30 ILCS 500/45-23, P.A. 102-1081, and 30 ILCS 500/45-24, P.A. 103-0470)","status":"active","effective":"Jan 1, 2023 (agencies may not procure single-use plastic disposable foodware for State parks or natural areas); Jan 1, 2024 or next contract renewal (state-contracted vendors at park and natural-area sites); Jan 1, 2025 (agencies may not procure polystyrene foam disposable food service containers agency-wide); Jan 1, 2026 or next contract renewal (state-contracted vendors at any State-owned or State-leased site)","scope":"State agencies and their contracted vendors must offer only compostable or recyclable foodware -- containers, bowls, straws, plates, trays, cartons, cups, lids, and cutlery -- in place of the prohibited single-use plastic (parks phase) and polystyrene foam (all-agency phase) items; compostable means meeting ASTM D6400 and certified by the Biodegradable Products Institute, recyclable means commonly accepted in local curbside residential recycling pickup; a 5 percent bid preference applies to otherwise-qualified bidders fulfilling agency or higher-education contracts with compostable or recyclable foodware (preferred contracts must still offer single-use plastic straws as an accessibility option); Illinois State Fair procurement is exempt, as are foam coolers, egg cartons, seafood-shipping ice chests, and raw-meat packaging","sectors":"State agencies and departments, institutions of higher education (bid preference), and vendors contracted through a State agency operating at State parks, natural areas, or any State-owned or State-leased site","source_label":"Illinois Compiled Statutes, 30 ILCS 500/45-23 and 45-24 (Illinois General Assembly / Legislative Reference Bureau)","source_url":"https://www.ilga.gov/Documents/legislation/ilcs/documents/003005000K45-24.htm","verified":"primary","footnote":"Verified from the current ILCS codification, which is decisive over the conflicting SB 58 bill-status synopses (that bill's Oct 1, 2026 repeal language concerns Degradable Plastic Act tracking provisions, not these Procurement Code sections). Deferred to this category from the foodware-use pass under the who-is-bound test: these sections bind state purchasing and contracting, not food vendors generally. The vendor-facing phases attach at contract renewal, so coverage of contracted sites keeps expanding after the stated dates."},{"category":"single-use-plastic","law":"Small Single-Use Plastic Bottle Act (SB 2960; Public Act 103-0934, signed Aug 9, 2024)","status":"active","effective":"Hotels with 50 or more rooms prohibited since July 1, 2025; all Illinois hotels regardless of size since Jan 1, 2026","scope":"Hotels may not provide small single-use plastic bottles (under 6 ounces) containing personal care products -- shampoo, hair conditioner, or bath soap -- in sleeping rooms or in bathrooms shared by the public or guests; the products may still be provided on request at other locations; a written warning issues for a first violation and civil penalties up to $500 apply for each violation thereafter; the act preempts inconsistent local regulation of small single-use plastic bottles","sectors":"Hotels and lodging (hospitality) -- not foodservice","source_label":"Illinois General Assembly (SB 2960 enrolled text, P.A. 103-0934)","source_url":"https://www.ilga.gov/documents/legislation/103/SB/PDF/10300SB2960.pdf","verified":"primary","footnote":"HOSPITALITY-NOT-FOODWARE CAVEAT: binds lodging operators over toiletry bottles, not foodservice packaging (MA EO 619 bottles-only precedent). Illinois' only statewide single-use-plastic product ban -- the state's foodservice plastics measure is the procurement-code preference already carried under procurement, and its foam bill remains unenacted. First Great Lakes state with a hospitality bottle law."}],"municipal":[]},"ME":{"name":"Maine","laws":[{"category":"organics-diversion","law":"LD 1065 (2025)","status":"scheduled","effective":"July 1, 2030; tightens July 1, 2032","scope":"At least 2 tons/week within 20 miles (2030), then at least 1 ton/week within 25 miles (2032)","sectors":"Commercial food scrap generators","source_label":"Maine Legislature (38 MRS 2147)","source_url":"https://legislature.maine.gov/statutes/38/title38sec2147.html","verified":"primary","footnote":"Enacted but not yet in force. Codified at 38 MRS 2147 (via Public Act 2025, c. 419)."},{"category":"foam-ban","law":"Polystyrene Foam Food Service Container Ban (LD 289, 2019; 38 MRSA ch. 15-A)","status":"active","effective":"Enforced July 1, 2021 (first state to enact, 2019)","scope":"Disposable food service containers composed in whole or in part of polystyrene foam (cups, bowls, plates, trays, cartons, lids)","sectors":"Covered establishments -- restaurants, stores, agricultural fairs; licensed hospitals and DHHS-funded meals-on-wheels programs exempt","source_label":"Maine DEP","source_url":"https://www.maine.gov/dep/waste/recycle/polystyrene-foam.html","verified":"primary","footnote":"Temporary exemption for raw-protein (meat, poultry, seafood, egg) foam packaging sold prepackaged at wholesale was extended to July 1, 2027 (LD 1306, 2025). Civil fine up to $100 per violation."},{"category":"pfas-packaging","law":"Toxics in Food Packaging PFAS prohibition (Chapter 80 Section 5 rule, adopted April 18, 2024, under 32 MRSA ch. 26-A)","status":"active","effective":"May 25, 2026 (statute sets the ban two years after the rule's May 25, 2024 effective date) -- in force as of five weeks ago","scope":"Plant-fiber food packaging intended for direct food contact and for short-term storage or freshly prepared food (nine specified categories), with PFAS intentionally introduced in any amount greater than incidental presence","sectors":"Manufacturers, suppliers, and distributors offering food packaging for sale or promotional purposes in Maine","source_label":"Maine DEP","source_url":"https://www.maine.gov/dep/safechem/packaging/index.html","verified":"primary","footnote":"Distinct from Maine's broader PFAS in Products Law (38 MRS 1614, most PFAS phased out by 2032), which generally exempts packaging -- this rule is the operative food-packaging ban. The same chapter has banned phthalates in food packaging since Jan 1, 2022."},{"category":"epr-packaging","law":"An Act to Support and Improve Municipal Recycling Programs and Save Taxpayer Money (LD 1541, 2021; 38 M.R.S. section 2146), as amended by LD 1423 (2025)","status":"scheduled","effective":"Enacted July 2021 -- the first state packaging EPR law in the nation; program rules (06-096 C.M.R. ch. 428) effective Dec 25, 2024, with the Appendix A materials list adopted by the Board of Environmental Protection in Feb 2026; the stewardship organization RFP issued June 15, 2026 (proposals due Aug 3, 2026); producer registration opens within 90 days after the selected SO makes a registration mechanism available, with start-up fees due within 180 days of the SO contract; first annual producer payments expected Sept 2027; program fully operational in 2027","scope":"Producers of consumer packaging material sold or distributed into Maine will pay into a packaging stewardship fund based on the amount and recyclability of their packaging; the fund reimburses participating municipalities for recycling and waste-management costs -- a municipal-reimbursement model distinct from the PRO-run systems in the other six states -- and invests in infrastructure and education; exemptions include low-revenue and low-tonnage producers and small perishable-food producers; LD 1423 (2025) narrowed covered packaging and aligned definitions with the later state programs","sectors":"Producers -- generally brand owners, or sole importers where the brand owner has no U.S. presence -- of packaging material for products sold in or into Maine; participating municipalities receive reimbursements","source_label":"Maine Department of Environmental Protection","source_url":"https://www.maine.gov/dep/waste/recycle/epr.html","verified":"primary","footnote":"Modeled scheduled, not active, under this pass's status rule: no producer obligation is currently enforceable because no stewardship organization is under contract, and producers cannot register until the SO selected from the June 15, 2026 RFP opens a registration mechanism. First enacted in the nation (2021) but now trailing the other six programs in implementation."},{"category":"single-use-plastic","law":"An Act To Eliminate Single-use Plastic Carry-out Bags (LD 1532, 2019; P.L. ch. 346; 38 M.R.S. section 1611)","status":"active","effective":"Signed June 17, 2019; statute effective April 22, 2020, with DEP enforcement (twice delayed for the pandemic) since July 1, 2021","scope":"All retail establishments -- expressly including stores, restaurants, and temporary or pop-up businesses such as farmers markets, food trucks, and fairs -- may provide only reusable bags or recycled paper bags at the point of sale, with a minimum 5-cent fee per recycled paper or reusable plastic bag retained by the retailer; compostable, biobased, and biodegradable plastic bags are prohibited the same as petroleum plastic; exemptions cover produce, bulk-item, and similar in-store bags","sectors":"Retail establishments statewide, including restaurants and temporary vendors","source_label":"Maine Department of Environmental Protection (single-use plastic bag ban)","source_url":"https://www.maine.gov/dep/waste/recycle/plastic-bag-film.html","verified":"primary","footnote":"Maine's bag statute is unusually explicit that compostable plastic bags are banned alongside conventional plastic -- a materials-claims point relevant to truth-in-labeling positioning. Maine has no statewide straw or accessories law (local ordinances only; the LD 602 straw bill did not pass). Distinct from LD 289, the foam statute carried under foam-ban, and from the EPR and PFAS statutes."}],"municipal":[]},"DC":{"name":"District of Columbia","laws":[{"category":"organics-diversion","law":"Zero Waste Omnibus Amendment Act of 2020 (DC Law 23-211); DC Code 8-1031.03a","status":"callout","effective":"Source separation required Jan 1, 2023; Mayor may extend to other entities beginning Jan 1, 2024","scope":"Large generators -- retail food store chains (3+ stores, 10,000+ sq ft combined), arenas/stadiums 15,000+ seats, hospitals/nursing homes 300+ beds, colleges/universities 500+ residential students","sectors":"Commercial and institutional large generators","source_label":"DC DOEE","source_url":"https://zerowaste.dc.gov/commercialfoodwaste","verified":"primary","footnote":"Shown as a callout, not shaded as a state (D.C. is not a state). Back-of-house source separation for large generators under DC Code 8-1031.03a. The Mayor may extend requirements to other entities within 35 miles of the Capitol dome beginning Jan 1, 2024."},{"category":"foam-ban","law":"Sustainable DC Omnibus Amendment Act of 2014 -- Foam Ban","status":"callout","effective":"Use ban Jan 1, 2016; retail-sale ban (foam food ware, coolers, packing peanuts) Jan 1, 2021","scope":"Disposable food service ware made of expanded polystyrene; since 2021 also the retail sale of foam food ware, foam storage containers, and loose-fill packaging","sectors":"All District businesses and organizations serving food or beverages; retailers since 2021","source_label":"DC DOEE","source_url":"https://doee.dc.gov/foam","verified":"primary","footnote":"Shown as a callout, not shaded as a state (D.C. is not a state). DOEE reports over 96% business compliance and reduced foam in Anacostia River trash traps. A companion requirement makes remaining single-use food service ware compostable or recyclable."},{"category":"foodware-use","law":"Sustainable DC Omnibus Amendment Act of 2014 -- compostable or recyclable disposable food service ware required (D.C. Law 20-142, sec. 403; D.C. Code 8-1533), amended by the Zero Waste Omnibus Amendment Act of 2020 (D.C. Law 23-211)","status":"callout","effective":"Oct 1, 2015 (District facilities, agencies, contractors, and lessees, with existing-inventory grace to Jan 1, 2017); Jan 1, 2017 (no food service entity may sell or provide food or beverages in disposable food service ware unless it is compostable or recyclable); DOEE enforcement of the business requirement began Jan 1, 2018","scope":"All disposable food service ware used to serve consumers -- takeout containers, bowls, plates, trays, cups, cutlery, straws, and stirrers -- must be compostable or recyclable as defined by the Mayor's List of Recyclables and Compostables; the Oct 2018 List update removed plastic straws and stirrers; mixed-material items such as foil-lined wraps and paper bags with plastic windows are banned; prepackaged food or beverages filled and sealed outside the District are exempt","sectors":"Restaurants and all District businesses and organizations selling or serving food or beverages, plus District facilities, agencies, departments, contractors, and lessees; the Department of Energy and Environment (DOEE) enforces with warning letters and fines","source_label":"DC DOEE (food service ware requirements) and D.C. Code 8-1533","source_url":"https://doee.dc.gov/foodserviceware","verified":"primary","footnote":"Shown as a callout, not shaded as a state (D.C. is not a state), consistent with the DC organics and foam entries. Companion section to the DC foam ban (D.C. Code 8-1532) in the same 2014 act -- the existing foam-ban entry already cross-references this requirement, so the reciprocal footnote convention is satisfied on both sides. The 2020 Zero Waste amendments added accessories-on-request and reusable-foodware grant provisions."}],"municipal":[]},"CO":{"name":"Colorado","laws":[{"category":"foam-ban","law":"Plastic Pollution Reduction Act (HB21-1162)","status":"active","effective":"Jan 1, 2024","scope":"Distribution of EPS products used as containers for ready-to-eat food; inventory purchased before Jan 1, 2024 may be used until depleted","sectors":"Retail food establishments (restaurants, cafeterias, and similar operations)","source_label":"Colorado General Assembly","source_url":"https://leg.colorado.gov/bills/hb21-1162","verified":"primary","footnote":"Enforcement is local: counties may impose civil penalties up to $500 (2nd violation) and $1,000 (3rd+), except against retail food establishments located within schools. Since July 1, 2024 localities may adopt stricter plastics rules (state preemption repealed). The same statute's carryout bag fee and plastic bag ban provisions are carried under single-use-plastic per the Oregon SB 543 convention, cross-referenced rather than double-counted."},{"category":"pfas-packaging","law":"HB22-1345 (2022) -- PFAS Chemicals Consumer Protection Act (C.R.S. 25-15-601 to -604)","status":"active","effective":"Jan 1, 2024","scope":"Food packages and packaging components used in direct contact with food and composed in substantial part of paper, paperboard, or other plant-fiber materials, with intentionally added PFAS","sectors":"Any person selling or distributing in Colorado; the Attorney General enforces","source_label":"Colorado General Assembly","source_url":"https://leg.colorado.gov/bills/hb22-1345","verified":"primary","footnote":"SB24-081 (2024) expanded the act: PFAS cookware banned Jan 1, 2026 and commercial food equipment banned Jan 1, 2028. The same 2022 act created cookware labeling rules and state PFAS-free procurement preferences."},{"category":"truth-in-labeling","law":"Compostables Labeling Act (SB23-253, 2023; C.R.S. 25-17-801 et seq.)","status":"active","effective":"Jul 1, 2024","scope":"Plastic products and food service products represented as compostable must be certified to ASTM D6400 or D6868 by an independent third party, display a certification logo, the word compostable where possible, and green symbols, colors, tinting, or design patterns, and may NOT display a chasing arrow resin identification code or recycling symbol of any form; non-certified products are barred from compostable-style tinting, color schemes, and terms and from words such as natural, biodegradable, degradable, decomposable, and oxo-degradable; products composed entirely of untreated wood, including fiber-based substrates, are exempt","sectors":"Producers marketing, advertising, or selling covered products in Colorado; the Colorado Department of Public Health and Environment administers","source_label":"Colorado Dept. of Public Health and Environment (Compostables Labeling Act)","source_url":"https://cdphe.colorado.gov/hm/compostable-product-labeling-act-faq","verified":"primary","footnote":"Non-compostable product accessories such as lids, straws, and labels should clearly differentiate themselves and describe recyclability or state landfill only."},{"category":"epr-packaging","law":"Producer Responsibility Program for Statewide Recycling Act (HB 22-1355, 2022; C.R.S. 25-17-701 to 25-17-716)","status":"active","effective":"Signed June 3, 2022; since July 1, 2025 a producer may not sell or distribute products using covered materials in Colorado unless participating in the program; annual producer responsibility dues began Jan 1, 2026; calendar-year-2025 supply data was due to the PRO May 31, 2026; CDPHE approved the Circular Action Alliance program plan in Dec 2025, with implementation beginning by summer 2026 and first PRO administrative dues to CDPHE by June 30, 2026","scope":"Producers of packaging, paper products, and food service ware -- explicitly among the covered materials -- fund a statewide recycling system that reimburses 100 percent of the net recycling-service costs of participating providers; Circular Action Alliance is the designated PRO (a separate individual program plan covers automotive lubricant packaging); exemptions include producers under roughly $5.5 million in prior-year revenue (inflation-adjusted annually by CDPHE rule) or under one ton of covered materials; eco-modulation bonuses reduce dues for recyclable and recycled-content design (recycled-content mandates themselves are outside this map's scope)","sectors":"Producers -- generally brand owners -- of packaging, paper products, and food service ware sold or distributed into Colorado","source_label":"Colorado Department of Public Health and Environment","source_url":"https://cdphe.colorado.gov/hm/epr-program","verified":"primary","footnote":"LITIGATION FLAG: the Independent Lubricant Manufacturers Association sued over the Colorado program in March 2026, challenging the PRO fee structure and the statute's restriction on disclosing program costs to customers; no injunction found as of this pass, and obligations remain in force. The second state program to reach full operation, after Oregon."},{"category":"single-use-plastic","law":"Plastic Pollution Reduction Act (HB21-1162) -- carryout bag fee and plastic bag ban provisions","status":"active","effective":"Signed July 6, 2021; minimum 10-cent carryout bag fee at large stores since Jan 1, 2023; single-use plastic carryout bags banned at stores and retail food establishments since Jan 1, 2024 (pre-2024 inventory could be supplied with the fee through June 1, 2024); recycled paper bags remain available at a minimum 10-cent fee, with 60 percent of fee revenue remitted quarterly to the local government since April 1, 2024","scope":"Stores may provide only recycled paper carryout bags at a fee; restaurants and small stores operating solely in Colorado with three or fewer locations may still provide plastic bags; the fee is waived for customers in federal or state food assistance programs; pharmaceutical, medical device, and dietary supplement packaging is outside the act; enforcement is local, with civil penalties up to $500 for a second violation and $1,000 for a third or subsequent violation","sectors":"Retail stores and retail food establishments; municipalities and counties (fee revenue and enforcement)","source_label":"Colorado General Assembly (HB21-1162 enacted summary)","source_url":"https://leg.colorado.gov/bills/hb21-1162","verified":"primary","footnote":"Same statute as the CO foam-ban entry (Oregon SB 543 convention) -- the EPS provisions remain modeled there and the bag provisions are carried here, cross-referenced rather than double-counted. Since July 1, 2024 localities may adopt stricter plastics rules (state preemption repealed), which several resort towns have used to restrict plastic water bottles and service ware."}],"municipal":[]},"VA":{"name":"Virginia","laws":[{"category":"foam-ban","law":"Expanded Polystyrene Food Service Container Ban (2021 legislation)","status":"active","effective":"July 1, 2025 (food vendors with 20+ Virginia locations); July 1, 2026 (all food vendors)","scope":"Dispensing prepared food in EPS food service containers -- cups, plates, bowls, trays, and hinged clamshells","sectors":"All food vendors, including restaurants, grocery stores, delis, caterers, food trucks, schools, and state/local government food service","source_label":"Virginia DEQ","source_url":"https://www.deq.virginia.gov/land-waste/waste-management/litter-prevention/foam-free-resources","verified":"primary","footnote":"Full all-vendor phase took effect July 1, 2026. Localities could grant one-year undue-hardship exemptions during phase 1; DEQ states no exemptions are provided for the 2026 all-vendor phase. A 2025 gubernatorial budget attempt to delay the ban failed."}],"municipal":[]},"DE":{"name":"Delaware","laws":[{"category":"foam-ban","law":"SB 51 (2023) -- Polystyrene Foam Food Service Packaging Ban (Title 16, Del. Code)","status":"active","effective":"July 1, 2025; penalties begin July 1, 2026","scope":"Providing ready-to-eat food or beverages in polystyrene foam containers; also bans plastic stirrers, cocktail picks, and sandwich picks, with plastic straws by request only","sectors":"Food establishments (restaurants, cafeterias, grocery stores, caterers)","source_label":"Delaware General Assembly","source_url":"https://legis.delaware.gov/BillDetail/130016","verified":"primary","footnote":"Exempt: seafood-processing/shipping coolers and packaging for raw or butchered meat, poultry, fish, seafood, eggs, fruits, or vegetables; health-care providers for food served to a patient or resident. Violations are administrative core-item violations under the Delaware Food Code -- licenses cannot be suspended or revoked for them."},{"category":"single-use-plastic","law":"Plastic Carryout Bag Ban and At-Store Recycling Program (HB 130, 2019, expanded by HB 212, 2021; 7 Del. C. section 6099A; 7 DE Admin. Code 1301 section 14)","status":"active","effective":"HB 130 effective Jan 1, 2021 for large retailers; HB 212 (signed Sept 30, 2021) extended the ban to ALL retail stores regardless of size effective July 1, 2022 and closed the thick-film loophole by requiring reusable bags be fabric with stitched handles or durable 10-mil plastic","scope":"All retail stores in Delaware may not provide plastic carryout bags of any thickness at the point of sale -- restaurants are the only exempted establishment type; stores may offer reusable or paper bags, or none; covered stores must continue operating at-store recycling drop-offs for plastic bags and film; exempt bags include produce, raw-protein, and prescription bags; DNREC enforces with administrative penalties up to $500 for a first violation, $1,000 for a second, and $2,000 for a third or subsequent violation","sectors":"Retail stores statewide; restaurants exempt","source_label":"Delaware Department of Natural Resources and Environmental Control (plastic carryout bag ban)","source_url":"https://dnrec.delaware.gov/waste-hazardous/recycling/plastic-bags/","verified":"primary","footnote":"Delaware's 10-mil reusable-bag threshold -- adopted from the New Jersey stitched-handle model -- is the thickest film standard of any state on this map. The restaurant exemption is the inverse of Maine's restaurant-inclusive statute; a useful contrast for foodservice content. Delaware has no statewide straw or accessories statute (bills have not passed). Distinct from SB 51, the foam statute carried under foam-ban."}],"municipal":[]},"OR":{"name":"Oregon","laws":[{"category":"foam-ban","law":"SB 543 (2023) -- ORS 459.465 to 459.477","status":"active","effective":"Jan 1, 2025","scope":"Food vendors may not use polystyrene foam containers for prepared food; sale of PS foam containers, foam coolers, and foam packing peanuts also banned. No existing-inventory allowance","sectors":"Food vendors (restaurants, grocery stores, delis, food carts) and any person selling or distributing covered foam products; DEQ has no authority to grant exemptions","source_label":"Oregon DEQ","source_url":"https://www.oregon.gov/deq/mm/production/pages/polystyrene.aspx","verified":"primary","footnote":"The same law bans intentionally added PFAS in foodware containers (tracked separately under the PFAS category). Fines range from $100 to $500 per day."},{"category":"pfas-packaging","law":"SB 543 (2023) -- ORS 459.465 to 459.477","status":"active","effective":"Jan 1, 2025","scope":"Foodware containers with intentionally added PFAS: food vendors may not use them for prepared food, and no person may sell or distribute them. Covers foodware containers rather than all food packaging","sectors":"Food vendors (restaurants, grocery stores, delis, food carts) and any person selling or distributing covered containers; DEQ has no authority to grant exemptions","source_label":"Oregon DEQ","source_url":"https://www.oregon.gov/deq/mm/production/pages/polystyrene.aspx","verified":"primary","footnote":"Same statute as Oregon's foam-ban entry -- one law tracked under two categories per the schema, not double-counted. Fines range from $100 to $500 per day."},{"category":"epr-packaging","law":"Plastic Pollution and Recycling Modernization Act (SB 582, 2021)","status":"active","effective":"Enacted 2021, effective Jan 1, 2022; program launched July 1, 2025 -- the first operating state packaging EPR program in the nation; producer PRO membership, supply reporting (calendar-year-2024 data reported March 31, 2025), and fee payments are in force; DEQ rule amendments for clarity go to the Environmental Quality Commission in early 2027","scope":"Producers of packaging, printing and writing paper, and food service ware -- an explicit covered-materials category -- sold or distributed into Oregon must join a producer responsibility organization and fund recycling-system modernization, including statewide collection lists, processor and responsible-end-market standards, and expanded collection; Circular Action Alliance is the only PRO with an approved program plan (approved Feb 21, 2025; amended plan response issued May 4, 2026); producers under $5 million in annual revenue or under one ton of covered materials are exempt","sectors":"Producers -- generally brand owners or importers -- of packaging, printing and writing paper, and food service ware introduced into Oregon","source_label":"Oregon Department of Environmental Quality (Plastic Pollution and Recycling Modernization Act)","source_url":"https://www.oregon.gov/deq/recycling/pages/modernizing-oregons-recycling-system.aspx","verified":"primary","footnote":"LITIGATION FLAG: in the NAW suit against Oregon DEQ (D. Or., filed July 2025), a Feb 6, 2026 preliminary injunction pauses DEQ enforcement ONLY for National Association of Wholesaler-Distributors members who had joined by that date (scope clarified by the court Apr 6, 2026); the program continues operating, the PRO continues collecting fees, and a five-day trial begins July 13, 2026 -- not modeled as enjoined. AF&PA's motion to intervene and its parallel injunction request were denied Apr 1, 2026 as untimely. Oregon HB 4030 (2026), which would carve berry and non-compostable meat, poultry, fish, and seafood packaging out of SB 582, is a pending bill excluded under the enacted-only rule. Distinct from Oregon SB 543, the foam and PFAS statute carried in those categories."},{"category":"single-use-plastic","law":"Sustainable Shopping Initiative (HB 2509, 2019; ORS 616.892) + single-use plastic straws law (SB 90, 2019; ORS 459A.757)","status":"active","effective":"Bag provisions effective Jan 1, 2020 (pandemic-era enforcement grace expired in 2020-2021); straw provisions effective on signing, June 13, 2019","scope":"Retail stores and restaurants may not provide single-use checkout bags and must charge at least 5 cents -- a floor, not a ceiling; localities may set higher fees -- for recycled paper bags (40 percent postconsumer content), reusable 4-mil plastic bags, or reusable fabric bags, though restaurants may provide paper bags free; food and beverage providers and convenience stores may provide single-use plastic straws only on request (drive-throughs may ask; health care settings exempt); bag violations are Class D violations up to $250 per day enforced locally, while straw enforcement belongs solely to state and county inspectors and SB 90 fully preempts differing local straw rules","sectors":"Retail stores, restaurants, food and beverage providers, and convenience stores statewide","source_label":"Oregon Department of Environmental Quality (single-use bag ban)","source_url":"https://www.oregon.gov/deq/mm/production/Pages/Bags.aspx","verified":"primary","footnote":"Folded entry carrying two 2019 statutes under the per-state folding rule. DEQ's legislative report on grocery bag use was due in 2025 under HB 2509 -- a data source worth pulling for content. Distinct from SB 543 (the foam and PFAS statute) and SB 582 (epr-packaging) -- no double-count; SB 543 carries no bag or straw provision, so no reciprocal edit is required on the Oregon foam entry."}],"municipal":[]},"MN":{"name":"Minnesota","laws":[{"category":"pfas-packaging","law":"Minn. Stat. 325F.075 -- Food Packaging; PFAS (enacted 2021)","status":"active","effective":"Jan 1, 2024","scope":"ALL food packages -- any container or component used to market, protect, handle, deliver, serve, contain, or store food or beverages, explicitly including inks, coatings, labels, closures, cushioning, shrink wrap, and shipping containers -- with intentionally added PFAS. Not limited to plant fiber","sectors":"Anyone manufacturing or knowingly selling, offering for sale, distributing, or offering for use in Minnesota; MPCA enforces and may coordinate with commerce and health","source_label":"Minnesota Pollution Control Agency","source_url":"https://www.pca.state.mn.us/air-water-land-climate/pfas-use-prohibitions","verified":"primary","footnote":"MPCA confirms there is no sell-through period and no statutory waiver authority -- one of the broadest state bans. Separate from Amara's Law (Minn. Stat. 116.943), whose 2026 PFAS reporting program exempts food packaging because it is already banned."},{"category":"truth-in-labeling","law":"Minn. Stat. 325E.046 -- labeling standards for covered products (2009 plastic-bag law expanded by Laws 2023, chapter 60, article 3, section 23)","status":"active","effective":"Jan 1, 2025 (2023 expansion to bags, food and beverage products, and packaging); Jan 1, 2026 (mandatory third-party nonprofit certification, now in force); original plastic-bag labeling standards date to 2009","scope":"Covered products (bags, food or beverage products such as plates, bowls, cups, lids, trays, straws, utensils, and containers, and packaging) may not be labeled biodegradable, degradable, or decomposable or imply landfill breakdown unless an adopted ASTM standard exists and the product is certified to it; a compostable label requires meeting ASTM D6400 or D6868 or being made solely of wood or paper with no additives or coatings, plus clear and prominent labeling that the product is intended for an industrial or commercial compost facility","sectors":"Manufacturers, distributors, wholesalers, and any person knowingly selling covered products in Minnesota; the Minnesota Pollution Control Agency enforces and may demand compliance information","source_label":"Minnesota Legislature (Revisor of Statutes)","source_url":"https://www.revisor.mn.gov/statutes/cite/325E.046","verified":"primary","footnote":"MPCA implementation guidance at pca.state.mn.us confirms the Jan 1, 2025 product standards and the Jan 1, 2026 certification requirement. Distinct from the Minnesota pfas-packaging entry (325F.075) -- different statute, different category."},{"category":"epr-packaging","law":"Packaging Waste and Cost Reduction Act (HF 3911, signed May 21, 2024; Minn. Stat. 115A.144 to 115A.1463)","status":"active","effective":"Producers were required to register with the PRO by July 1, 2025; calendar-year-2025 supply data was due May 31, 2026; the MPCA preliminary needs assessment is complete (issued Feb 2026) with the full needs assessment due Dec 31, 2026; PRO stewardship plan due Oct 1, 2028; from Jan 1, 2029 covered materials may not be introduced without a written PRO agreement under an approved plan; producers reimburse at least 90 percent of covered service costs by 2031; by Jan 1, 2032 all packaging, food packaging, and paper products must be reusable, refillable, recyclable, or compostable","scope":"Producers of packaging, food packaging -- an explicit statutory category covering materials used to market, protect, handle, deliver, serve, contain, or store food and beverages -- and paper products sold, distributed, or shipped into Minnesota, including e-commerce shipments; Circular Action Alliance was confirmed as the PRO on Feb 18, 2025; de minimis exemption for producers introducing under one ton of covered material or earning under $2 million in global gross revenue; the MPCA will set postconsumer-recycled-content requirements under the program (recycled-content mandates are outside this map's scope) and rulemaking under Minn. R. ch. 7035 is underway","sectors":"Producers -- generally brand owners, manufacturers, or importers -- of packaging, food packaging, and paper products introduced into Minnesota","source_label":"Minnesota Pollution Control Agency","source_url":"https://www.pca.state.mn.us/air-water-land-climate/extended-producer-responsibility-for-packaging","verified":"primary","footnote":"The Jan 1, 2032 reusable-refillable-recyclable-or-compostable design mandate is modeled here within the EPR lawObject, not as a separate truth-in-labeling or single-use-plastic entry, per the boundary rules. Distinct from Minn. Stat. 325F.075 (pfas-packaging) and Minn. Stat. 325E.046 (truth-in-labeling) already on the map."}],"municipal":[{"city":"Minneapolis, MN","category":"foodware-use","law":"Green To Go -- Environmentally Acceptable Packaging Ordinance (Minneapolis Code of Ordinances Chapter 204; original 1989, renamed and expanded 2015)","status":"active","effective":"Apr 22, 2015 (Green To Go: food and beverages for immediate consumption or to-go must be in environmentally acceptable packaging; first such city requirement in Minnesota); original environmentally acceptable packaging ordinance dates to 1989, expanded 1996","scope":"Food or beverages intended for immediate consumption may only be sold in packaging that is reusable, recyclable (plastics 1, 2, and 5 allowed; black plastic and polystyrene foam not allowed), or compostable (BPI-certified compostable plastics); food businesses must provide collection bins for each material type used, recycle recyclables, and compost compostable plastics","sectors":"Food establishments including restaurants, grocery and convenience stores, vending, and food service operations in schools; caterers, hospitals, and nursing homes exempt; the Minneapolis Health Department environmental health division enforces","source_label":"City of Minneapolis (Green To Go, Code Chapter 204)","source_url":"https://www.minneapolismn.gov/business-services/business-assistance/run/food-business-rules/green-to-go/","verified":"primary","footnote":"First city in Minnesota to require recyclable, reusable, or compostable to-go containers; St. Paul (Green To Go, Jan 1, 2022), St. Louis Park, Edina, and Roseville have since adopted similar ordinances -- Minneapolis is carried as the landmark. Not subsumed: Minnesota's statewide law (325E.046) governs labeling only, not use."}]},"HI":{"name":"Hawaii","laws":[{"category":"pfas-packaging","law":"Act 152 (HB 1644, 2022) -- HRS 321-602","status":"active","effective":"Dec 31, 2024","scope":"Four plant-fiber food packaging categories -- wraps and liners, plates, food boats, and pizza boxes -- with PFAS intentionally introduced in any amount","sectors":"Manufacture, sale, offer for sale, and distribution for sale or use statewide; manufacturers, kitchen supply distributors, retailers, wholesalers, and food establishments","source_label":"Hawaii Department of Health","source_url":"https://health.hawaii.gov/food-drug/pfas-in-food-packaging/","verified":"primary","footnote":"The four categories mirror Washington Ecology's first safer-alternatives assessment. New jurisdiction for this map: Hawaii has no state-level entry in other categories yet (its foam coverage is county-by-county -- see the foam-pass gap flag). DOH advises using up existing stock and ordering compliant packaging going forward."}],"municipal":[{"city":"Honolulu (City and County), HI","category":"single-use-plastic","law":"Disposable Food Ware Ordinance (Bill 40, 2019; Ordinance 19-30), with prior plastic bag ordinances 12-8, 14-29, and 17-37","status":"active","effective":"Ordinance 19-30 signed Dec 15, 2019; full plastic checkout bag ban (closing thick-film and compostable-plastic loopholes, extending to restaurants and food takeout) and by-request-only non-plastic utensils, straws, stirrers, and picks in force since April 1, 2021; the ban on providing or selling polystyrene foam food ware and disposable plastic service ware and food ware fully enforced since Sept 6, 2022 after pandemic delays and industry exemptions expired","scope":"All businesses and food vendors in the City and County of Honolulu -- roughly 72 percent of Hawaii's population -- may not provide plastic checkout bags or disposable plastic service ware; disposable plastic straws remain available on request for customers with medical or physical conditions; exemptions cover raw-protein and produce packaging, prepackaged and shelf-stable foods, and hardship or industry exemptions of up to two years; enforcement by the Department of Environmental Services runs warning first, then $100 to $1,000 per day","sectors":"All Honolulu businesses and food vendors","source_label":"City and County of Honolulu, Department of Environmental Services (Ordinance 19-30)","source_url":"https://www.honolulu.gov/env/ref/ordinance-19-30-bill-40/","verified":"primary","footnote":"LANDMARK ENTRY: Hawaii has no statewide bag or single-use-plastic statute, but all four counties -- Kauai (2011), Maui (2011), Hawaii County (2013), and Honolulu (2015, tightened 2017 and 2019) -- ban plastic checkout bags, making the prohibition de facto statewide; Honolulu alone represents the picture per the SF-redundancy convention. Ordinance 19-30 also bans foam food ware and plastic food ware islandwide -- noted here rather than modeled as separate municipal foam or foodware entries. Hawaii's statewide entry on this map remains the Act 152 PFAS law; its procurement and county foam bills remain unenacted watch items."}]},"NM":{"name":"New Mexico","laws":[{"category":"pfas-packaging","law":"PFAS Protection Act (HB 212, 2025), implemented by Rule 20.13.2 NMAC","status":"scheduled","effective":"Jan 1, 2027 (food packaging, cookware, dental floss, juvenile products, firefighting foam); more categories Jan 1, 2028; near-total ban Jan 1, 2032 absent a currently-unavoidable-use determination","scope":"Food packaging with intentionally added PFAS; notable statutory exemption for fluoropolymers; manufacturers must report PFAS content to NMED and apply a universal PFAS warning label to covered products manufactured after Jan 1, 2027","sectors":"Manufacturers, sellers, and distributors in New Mexico; NMED and the Environmental Improvement Board implement and enforce","source_label":"New Mexico Environment Department","source_url":"https://www.env.nm.gov/pfas/pfas-protection-act-hb212/","verified":"primary","footnote":"Third state (after Maine and Minnesota) with a full PFAS phase-out framework, and the first with a universal PFAS product-labeling requirement. New jurisdiction for this map."}],"municipal":[]}};
 var NAMES={"AL":"Alabama","AK":"Alaska","AZ":"Arizona","AR":"Arkansas","CA":"California","CO":"Colorado","CT":"Connecticut","DE":"Delaware","DC":"District of Columbia","FL":"Florida","GA":"Georgia","HI":"Hawaii","ID":"Idaho","IL":"Illinois","IN":"Indiana","IA":"Iowa","KS":"Kansas","KY":"Kentucky","LA":"Louisiana","ME":"Maine","MD":"Maryland","MA":"Massachusetts","MI":"Michigan","MN":"Minnesota","MS":"Mississippi","MO":"Missouri","MT":"Montana","NE":"Nebraska","NV":"Nevada","NH":"New Hampshire","NJ":"New Jersey","NM":"New Mexico","NY":"New York","NC":"North Carolina","ND":"North Dakota","OH":"Ohio","OK":"Oklahoma","OR":"Oregon","PA":"Pennsylvania","RI":"Rhode Island","SC":"South Carolina","SD":"South Dakota","TN":"Tennessee","TX":"Texas","UT":"Utah","VT":"Vermont","VA":"Virginia","WA":"Washington","WV":"West Virginia","WI":"Wisconsin","WY":"Wyoming"};
 var CATLABEL={"organics-diversion":"Organics diversion","foam-ban":"Foam / EPS ban","pfas-packaging":"PFAS in packaging","truth-in-labeling":"Truth-in-labeling","single-use-plastic":"Single-use plastics","epr-packaging":"EPR (packaging)","foodware-use":"Foodware-use mandate","procurement":"Green procurement","climate-disclosure":"SB 253 & 261"};
 var root=document.getElementById("eefw");
 var panel=document.getElementById("eefw-panel");
 var emptyHTML=document.getElementById("eefw-empty").outerHTML;
 var activeCat="all", selected=null;
 var BADGE={active:["#00a94f","Active"],scheduled:["#e6a817","Scheduled"],pending:["#9aa7b0","Pending"],callout:["#007a4d","Callout"]};
 function esc(s){return (s==null?"":String(s)).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");}
 function lawsFor(code,cat){var d=DATA[ code];if(!d)return[];var L=d.laws||[];return cat==="all"?L:L.filter(function(l){return l.category===cat;});}
 function catHasData(cat){for(var k in DATA){if(lawsFor(k,cat).length)return true;}return false;}
 function stateColor(code){
  var L=lawsFor(code,activeCat).filter(function(l){return l.status!=="callout";});
  if(!L.length)return null;
  var hasActive=L.some(function(l){return l.status==="active";});
  var hasSched=L.some(function(l){return l.status==="scheduled";});
  return hasActive?"#00a94f":(hasSched?"#e6a817":null);
 }
 function recolor(){
  var paths=root.querySelectorAll(".eefw-state");
  for(var i=0;i<paths.length;i++){
   var p=paths[i],code=p.getAttribute("data-st"),c=stateColor(code);
   p.setAttribute("fill",c||"#d5ddd6");
   p.setAttribute("stroke",c?"#006837":"#b7c2b9");
   var nm=NAMES[ code]||code;
   var n=lawsFor(code,activeCat).length;
   p.setAttribute("aria-label",nm+" -- "+(n?(n+" law"+(n>1?"s":"")+" in view"):"No state law in this view"));
  }
  var sws=root.querySelectorAll(".eefw-chip");
  for(var j=0;j<sws.length;j++){
   var g=sws[j],code2=g.getAttribute("data-st");
   var sw=g.querySelector(".eefw-chip-sw"); if(!sw)continue;
   if(g.classList.contains("eefw-chip-callout")){continue;}
   var c2=stateColor(code2);
   sw.setAttribute("fill",c2||"#d5ddd6"); sw.setAttribute("stroke",c2?"#006837":"#b7c2b9");
  }
  var counts={active:0,scheduled:0};
  for(var k in DATA){var col=stateColor(k);if(col==="#00a94f")counts.active++;else if(col==="#e6a817")counts.scheduled++;}
  var note=document.getElementById("eefw-lgnote");
  if(note){note.textContent=(activeCat==="all"?"All categories: ":"")+counts.active+" active state"+(counts.active===1?"":"s")+(counts.scheduled?(" \u00b7 "+counts.scheduled+" scheduled"):"")+(catHasData(activeCat)?"":" \u00b7 research pass pending for this category");}
 }
 function lawBlock(l){
  var b=BADGE[l.status]||BADGE.active;
  var src=l.source_url?('<a href="'+esc(l.source_url)+'" target="_blank" rel="noopener">'+esc(l.source_label)+'</a>'):(esc(l.source_label)+' <span class="eefw-pending">source link pending</span>');
  return '<div class="eefw-lawblock">'
   +'<span class="eefw-cat-tag">'+esc(CATLABEL[l.category]||l.category)+'</span>'
   +'<span class="eefw-badge"><span class="d" style="background:'+b[0]+'"></span>'+b[1]+'</span>'
   +(l.carveout?('<span class="eefw-carveout">'+esc(l.carveout)+'</span>'):'')
   +'<div class="eefw-field"><p class="l">Law / citation</p><p class="val">'+esc(l.law)+'</p></div>'
   +(l.effective?('<div class="eefw-field"><p class="l">Effective date(s)</p><p class="val">'+esc(l.effective)+'</p></div>'):'')
   +(l.scope?('<div class="eefw-field"><p class="l">Scope</p><p class="val">'+esc(l.scope)+'</p></div>'):'')
   +(l.sectors?('<div class="eefw-field"><p class="l">Covered sectors</p><p class="val">'+esc(l.sectors)+'</p></div>'):'')
   +(l.footnote?('<div class="eefw-note"><span class="l">Note</span>'+esc(l.footnote)+'</div>'):'')
   +'<div class="eefw-src">Primary source: '+src+'</div>'
   +'</div>';
 }
 function render(code){
  var d=DATA[ code];var nm=(d&&d.name)||NAMES[ code]||code;
  var L=lawsFor(code,activeCat);
  var all=lawsFor(code,"all");
  var html='<div class="eefw-detail"><p class="eefw-p-eyebrow">'+(code==="DC"?"District":"State")+'</p><h3 class="eefw-p-name">'+esc(nm)+'</h3>';
  if(L.length){
   var order=["organics-diversion","foam-ban","pfas-packaging","truth-in-labeling","single-use-plastic","epr-packaging","foodware-use","procurement"];
   L=L.slice().sort(function(a,b2){return order.indexOf(a.category)-order.indexOf(b2.category);});
   for(var i=0;i<L.length;i++)html+=lawBlock(L[i]);
   if(activeCat!=="all"&&all.length>L.length){html+='<div class="eefw-note"><span class="l">Also</span>'+esc(nm)+' has '+(all.length-L.length)+' law(s) in other categories -- switch to All categories to see them.</div>';}
  }else{
   html+='<span class="eefw-badge eefw-b-none"><span class="d" style="background:#b7c2b9"></span>No state law in this view</span>'
   +'<div class="eefw-field"><p class="val">'+(activeCat==="all"?'No state-level law in any mapped category yet.':(catHasData(activeCat)?'No state-level law in this category.':'This category\u2019s research pass has not run yet.'))+'</p></div>';
  }
  var muni=(d&&d.municipal)||[];
  if(activeCat!=="all")muni=muni.filter(function(m){return m.category===activeCat;});
  if(muni.length){html+='<div class="eefw-muni"><h4>Notable local ordinances</h4>';for(var m=0;m<muni.length;m++){html+='<div class="eefw-field"><p class="l">'+esc(muni[m].city)+'</p></div>'+lawBlock(muni[m]);}html+='</div>';}
  html+='</div>';panel.innerHTML=html;
 }
 function clearSel(){var s=root.querySelectorAll(".eefw-sel");for(var i=0;i<s.length;i++)s[i].classList.remove("eefw-sel");}
 function select(code){if(!DATA[ code]&&!NAMES[ code])return;selected=code;clearSel();var same=root.querySelectorAll('[data-st="'+code+'"]');for(var i=0;i<same.length;i++)same[i].classList.add("eefw-sel");render(code);}
 function setCat(cat,btn){activeCat=cat;var fs=root.querySelectorAll(".eefw-f");for(var i=0;i<fs.length;i++){fs[i].classList.remove("eefw-f-on");fs[i].setAttribute("aria-selected","false");}btn.classList.add("eefw-f-on");btn.setAttribute("aria-selected","true");recolor();if(selected)render(selected);else panel.innerHTML=emptyHTML;}
 var fbtns=root.querySelectorAll(".eefw-f");
 for(var i=0;i<fbtns.length;i++){(function(btn){
  var cat=btn.getAttribute("data-cat");
  if(cat!=="all"&&!catHasData(cat)){btn.classList.add("eefw-f-empty");btn.title="Research pass pending";}
  btn.addEventListener("click",function(){setCat(cat,btn);});
 })(fbtns[i]);}
 var nodes=root.querySelectorAll("[data-st]");
 function wire(el){el.addEventListener("click",function(){select(el.getAttribute("data-st"));});el.addEventListener("keydown",function(e){if(e.key==="Enter"||e.key===" "){e.preventDefault();select(el.getAttribute("data-st"));}});}
 for(var i2=0;i2<nodes.length;i2++){wire(nodes[i2]);}
 /* ---- EE Legislation Map email gate (eelg) ---- */
 var EELG=(function(){
  var K_EMAIL="eeLegisEmail",K_TS="eeLegisEmailTs",WINDOW_MS=90*24*60*60*1000;
  var sessionGrant=false,busy=false,pendingState="",leadType="";
  var ov=document.getElementById("eelg-overlay");
  var nameIn=document.getElementById("eelg-name"),emailIn=document.getElementById("eelg-email");
  var nameErr=document.getElementById("eelg-name-err"),emailErr=document.getElementById("eelg-email-err");
  var goBtn=document.getElementById("eelg-go"),xBtn=document.getElementById("eelg-x");
  var chips=document.getElementById("eelg-chips").querySelectorAll(".eelg-chip");
  function stored(){try{var ts=parseInt(localStorage.getItem(K_TS)||"0",10);
   return !!localStorage.getItem(K_EMAIL)&&ts>0&&(Date.now()-ts)<WINDOW_MS;}catch(e){return false;}}
  function unlocked(){return sessionGrant||stored();}
  function uuid4(){try{if(window.crypto&&crypto.randomUUID)return crypto.randomUUID();}catch(e){}
   return "xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx".replace(/[xy]/g,function(c){
    var r=Math.random()*16|0,v=c==="x"?r:(r&0x3|0x8);return v.toString(16);});}
  function consent(){return (typeof window.EE_MARKETING_CONSENT==="undefined")?true:!!window.EE_MARKETING_CONSENT;}
  function fireLead(eventId,lt){
   try{
    if(typeof window.fbq==="function"){
     window.fbq("track","Lead",{lead_type:lt,content_name:"legislation-map"},{eventID:eventId});}
    if(typeof window.lintrk==="function"&&window.EE_LI_CONVERSION_ID){
     window.lintrk("track",{conversion_id:window.EE_LI_CONVERSION_ID});}
    if(typeof window.gtag==="function"){
     window.gtag("event","generate_lead",{tool:"legislation-map",lead_type:lt});}
   }catch(e){/* trackers must never break the gate */}
  }
  function grant(captured,email,eventId,lt){
   sessionGrant=true;
   if(captured){
    try{localStorage.setItem(K_EMAIL,email);localStorage.setItem(K_TS,String(Date.now()));}catch(e){}
    if(consent())fireLead(eventId,lt);
   }
   close();
   if(pendingState){var s=pendingState;pendingState="";eelgSelect(s);}
  }
  function open(code){pendingState=code||"";ov.classList.add("eelg-open");
   try{nameIn.focus();}catch(e){}}
  function close(){ov.classList.remove("eelg-open");busy=false;goBtn.disabled=false;
   goBtn.textContent="View state details";}
  function submit(){
   if(busy)return;
   var nm=(nameIn.value||"").replace(/^\s+|\s+$/g,"");
   var em=(emailIn.value||"").replace(/^\s+|\s+$/g,"");
   var emOk=/^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/.test(em);
   nameErr.classList.toggle("eelg-show",!nm);
   emailErr.classList.toggle("eelg-show",!emOk);
   if(!nm||!emOk)return;
   busy=true;goBtn.disabled=true;goBtn.textContent="One moment...";
   var eventId=uuid4(),lt=leadType||"";
   var payload={name:nm,email:em,lead_type:lt,zip:pendingState||"",
    timestamp:new Date().toISOString(),userAgent:navigator.userAgent,
    event_id:eventId,source:"legislation-map"};
   var url=window.EELEGIS_GATE_URL||"PASTE_WEB_APP_URL_HERE";
   if(!url||url==="PASTE_WEB_APP_URL_HERE"){grant(false);return;} /* misconfigured -> fail open, no capture */
   fetch(url,{method:"POST",headers:{"Content-Type":"text/plain;charset=utf-8"},
    body:JSON.stringify(payload)
   }).then(function(r){if(!r||!r.ok)throw new Error("http");return r.json();
   }).then(function(j){grant(!!(j&&j.success),em,eventId,lt);
   }).catch(function(){grant(false);}); /* fail open */
  }
  for(var ci=0;ci<chips.length;ci++){(function(chip){
   chip.addEventListener("click",function(){
    var was=chip.classList.contains("eelg-on");
    for(var k=0;k<chips.length;k++)chips[k].classList.remove("eelg-on");
    if(!was){chip.classList.add("eelg-on");leadType=chip.getAttribute("data-lt");}
    else{leadType="";}
   });})(chips[ci]);}
  goBtn.addEventListener("click",submit);
  emailIn.addEventListener("keydown",function(e){if(e.key==="Enter")submit();});
  nameIn.addEventListener("keydown",function(e){if(e.key==="Enter")submit();});
  xBtn.addEventListener("click",close);
  ov.addEventListener("click",function(e){if(e.target===ov)close();});
  document.addEventListener("keydown",function(e){
   if(e.key==="Escape"&&ov.classList.contains("eelg-open"))close();});
  return {unlocked:unlocked,open:open};
 })();
 var eelgSelect=select;
 select=function(code){
  if(EELG.unlocked()){eelgSelect(code);}
  else{EELG.open(code);}
 };
 recolor();
})();
